      contextId,
      acquirePermit,
      recordHostStart,
      recordHostFinish,
      finishPermit,
      acquireCacheFlight,
      releaseCacheFlight,
      renewCacheFlight,
      writeCacheFlight,
      invalidateCacheWrites,
