    const { items, initialIndex } = imageSet;
    if (!items.length) return;
    const minimumCommentLength = lightboxCommentMinimumLength();
    const lb = document.createElement('div');
    lb.className = 'ldp-lightbox';
    lb.setAttribute('role', 'dialog');
