  function resolveOriginalSrc(imgEl) {
    const a = imgEl.closest('a.lightbox, a[href]');
    if (a && a.getAttribute('href')) {
      const href = a.getAttribute('href');
      if (/\.(png|jpe?g|gif|webp|bmp|avif)(\?|#|$)/i.test(href) || a.classList.contains('lightbox')) {
        return href;
      }
    }
    return imgEl.getAttribute('data-large-src') || imgEl.currentSrc || imgEl.src;
  }

  /* ============ 4. 已读追踪器 ============ */
  function createReadTracker(topicId, scrollRoot, requestScheduler, onReadConfirmed) {
    const dwell = new Map();
    const reported = new Map();
    const observedNodes = new Set();
    const viewportNodes = new Set();
    const pendingVisibleCallbacks = new Map();
    let tickTimer = null, flushTimer = null, readFlushTimer = null;
    let started = false, flushRunning = false, initialReadFlushPending = false;
    let readFlushDueAt = 0;
    let initialReadRetryAt = 0;
    let readChallengeAttempted = false;

    const notifyReadConfirmed = (postNumbers) => {
      if (typeof onReadConfirmed !== 'function') return;
      try {
        onReadConfirmed(postNumbers);
      } catch (error) {
        console.warn('[LDP] sync confirmed post read state failed', error);
      }
    };

    const io = new IntersectionObserver((entries) => {
      entries.forEach((en) => {
        const pn = +en.target.dataset.postNumber;
        if (!pn) return;
        const intersection = en.intersectionRect;
        const inViewport = en.isIntersecting &&
          intersection.width > 0 && intersection.height > 0;
        if (inViewport) viewportNodes.add(en.target);
        else viewportNodes.delete(en.target);
        const onVisible = inViewport && pendingVisibleCallbacks.get(en.target);
        if (onVisible) {
          pendingVisibleCallbacks.delete(en.target);
          onVisible();
          if (!observedNodes.has(en.target)) {
            viewportNodes.delete(en.target);
            io.unobserve(en.target);
          }
        }
      });
    }, { root: scrollRoot, threshold: 0 });

    const tick = () => {
      if (initialReadFlushPending) scheduleReadFlush();
    };

    const scheduleReadFlush = () => {
      if (readFlushTimer || !started || !initialReadFlushPending ||
          document.visibilityState !== 'visible') return;
      const now = Date.now();
      const dueAt = Math.max(readFlushDueAt || now + FLUSH_INTERVAL, initialReadRetryAt);
      readFlushTimer = setTimeout(() => {
        readFlushTimer = null;
        if (!started || !initialReadFlushPending || Date.now() < initialReadRetryAt) return;
        void flush({ priority: POST_REQUEST_PRIORITY.background });
      }, Math.max(0, dueAt - now));
    };

    const flush = async (options = {}) => {
      if (flushRunning) return false;
      if (initialReadRetryAt > Date.now()) return false;
      if (options.force !== true && readFlushDueAt > Date.now()) return false;
      const requestState = requestScheduler && requestScheduler.snapshot();
      if (options.force !== true && requestState && (
        requestState.active > 0 || requestState.queued > 0 || requestState.coolingDown
      )) return false;
      const params = { topic_id: topicId };
      let total = 0, any = false;
      const submittedPostNumbers = [];
      dwell.forEach((ms, pn) => {
        if (ms < READ_THRESHOLD) return;
        const inc = ms - (reported.get(pn) || 0);
        if (inc <= 0) return;
        params[`timings[${pn}]`] = inc;
        total += inc;
        reported.set(pn, ms);
        submittedPostNumbers.push(pn);
        any = true;
      });
      if (!any) {
        initialReadFlushPending = false;
        readFlushDueAt = 0;
        return false;
      }
      if (readFlushTimer) clearTimeout(readFlushTimer);
      readFlushTimer = null;
      flushRunning = true;
      const retryInitialReadFlush = initialReadFlushPending;
      initialReadFlushPending = false;
      readFlushDueAt = 0;
      params.topic_time = total;
      let challengeRecovery = null;
      try {
        await apiSend(
          `${BASE}/topics/timings`,
          'POST',
          params,
          {
            'Accept': '*/*',
            'Discourse-Background': 'true',
            'Discourse-Logged-In': 'true',
            'Discourse-Present': 'true',
            'X-SILENCE-LOGGER': 'true',
          },
          {
            priority: Number.isFinite(options.priority)
              ? options.priority
              : POST_REQUEST_PRIORITY.background,
          }
        );
        initialReadRetryAt = 0;
        notifyReadConfirmed(submittedPostNumbers);
        return true;
      } catch (e) {
        initialReadFlushPending = initialReadFlushPending || retryInitialReadFlush;
        if (initialReadFlushPending) {
          initialReadRetryAt = Date.now() + (e && e.cloudflareMitigated ? 5 * 60 * 1000 : FLUSH_INTERVAL);
        }
        Object.keys(params).forEach((k) => {
          const m = k.match(/^timings\[(\d+)\]$/);
          if (m) reported.set(+m[1], (reported.get(+m[1]) || 0) - params[k]);
        });
        if (e && e.cloudflareMitigated && !readChallengeAttempted) {
          readChallengeAttempted = true;
          challengeRecovery = {
            params: Object.assign({}, params),
            postNumbers: submittedPostNumbers.slice(),
          };
        }
      } finally {
        flushRunning = false;
        if (initialReadFlushPending && Date.now() >= initialReadRetryAt) scheduleReadFlush();
      }
      if (challengeRecovery) {
        const confirmedByFormPost = () => {
          challengeRecovery.postNumbers.forEach((postNumber) => {
            const increment = Number(challengeRecovery.params[`timings[${postNumber}]`]) || 0;
            reported.set(postNumber, Math.max(0, reported.get(postNumber) || 0) + increment);
          });
          initialReadRetryAt = 0;
          initialReadFlushPending = false;
          notifyReadConfirmed(challengeRecovery.postNumbers);
        };
        openCloudflareChallengePopup(`${BASE}/topics/timings`, {
          formParams: challengeRecovery.params,
          onFormSuccess: confirmedByFormPost,
          verify: async () => {
            initialReadRetryAt = 0;
            return flush({ force: true, priority: POST_REQUEST_PRIORITY.visible });
          },
        });
      }
      return false;
    };

    const pauseTimers = () => {
      clearInterval(tickTimer);
      clearInterval(flushTimer);
      clearTimeout(readFlushTimer);
      tickTimer = null;
      flushTimer = null;
      readFlushTimer = null;
    };

    const resumeTimers = () => {
      if (!started || document.visibilityState !== 'visible') return;
      if (!tickTimer) tickTimer = setInterval(tick, 1000);
      if (!flushTimer) flushTimer = setInterval(flush, FLUSH_INTERVAL);
      if (initialReadFlushPending) scheduleReadFlush();
    };

    const onVisibilityChange = () => {
      if (!started) return;
      if (document.visibilityState === 'visible') {
        resumeTimers();
        return;
      }
      tick();
      pauseTimers();
      flush({ force: true });
    };

    return {
      observe(node) {
        if (!node) return;
        observedNodes.add(node);
        io.observe(node);
        const postNumber = +(node.dataset && node.dataset.postNumber || 0);
        if (postNumber && !dwell.has(postNumber)) {
          dwell.set(postNumber, READ_THRESHOLD);
          if (!initialReadFlushPending) readFlushDueAt = Date.now() + FLUSH_INTERVAL;
          initialReadFlushPending = true;
          if (started) scheduleReadFlush();
        }
      },
      unobserve(node) {
        if (!node) return;
        observedNodes.delete(node);
        viewportNodes.delete(node);
        io.unobserve(node);
      },
      runWhenVisible(node, callback) {
        if (!node || typeof callback !== 'function') return false;
        if (viewportNodes.has(node) || readerPostNodeInViewport(node, scrollRoot)) {
          callback();
          return true;
        }
        pendingVisibleCallbacks.set(node, callback);
        io.observe(node);
        return false;
      },
      start() {
        if (started) return;
        started = true;
        document.addEventListener('visibilitychange', onVisibilityChange);
        resumeTimers();
        if (initialReadFlushPending) scheduleReadFlush();
      },
      stop() {
        if (!started) return;
        if (document.visibilityState === 'visible') tick();
        started = false;
        pauseTimers();
        document.removeEventListener('visibilitychange', onVisibilityChange);
        io.disconnect();
        observedNodes.clear();
        viewportNodes.clear();
        pendingVisibleCallbacks.clear();
        flush({ force: true });
      },
      retryPending() {
        initialReadRetryAt = 0;
        if (initialReadFlushPending) {
          return flush({ force: true, priority: POST_REQUEST_PRIORITY.visible });
        }
        return Promise.resolve(false);
      },
    };
  }

  /* ============ 5. 分块加载（init 带 Discourse 浏览追踪头 + 重试保护） ============ */
  function createLoader(topicId, requestScheduler, runtimeConfig) {
    const pageSize = runtimeConfig.pageSize;
    const onlyOpBatchFloor = Math.min(
      PERFORMANCE_LIMITS.pageSize.max,
      Math.max(pageSize, runtimeConfig.requestMaxConcurrent <= 1 ? 32 : 40)
    );
    let onlyOpPageSize = onlyOpBatchFloor;
    let stream = [];
    const cache = new Map();
    const postByNumber = new Map();
    const unavailablePostNumbers = new Set();
    const pendingPostRequests = new Map();
    let streamIndexById = new Map();
    const requestController = new AbortController();
    let cursor = 0;
    let onlyOpCursor = 0;
    let onlyOpSkippedCount = 0;
    let topic = null;
    let failStreak = 0;
    let onlyOpFailStreak = 0;
    let refreshRequest = null;
    let initializedFromCache = false;
    let stopTopicCacheSync = () => {};

    const growOnlyOpBatch = () => {
      let requestState = null;
      try { requestState = requestScheduler && requestScheduler.snapshot(); } catch (error) {}
      const shortPressure = requestState
        ? Number(requestState.shortWindowCount || 0) / Math.max(1, Number(requestState.shortWindowBudget) || 1)
        : 0;
      const longPressure = requestState
        ? Number(requestState.longWindowCount || 0) / Math.max(1, Number(requestState.longWindowBudget) || 1)
        : 0;
      const pressured = requestState && (
        requestState.coolingDown ||
        ['10s', '60s'].includes(requestState.blockingReason) ||
        Number(requestState.globalQueued || 0) > 0 ||
        Math.max(shortPressure, longPressure) >= 0.7
      );
      onlyOpPageSize = Math.min(
        PERFORMANCE_LIMITS.pageSize.max,
        onlyOpPageSize + (pressured ? 12 : 8)
      );
    };

    const adjustOnlyOpBatchAfterError = (error) => {
      const status = Number(error && error.status || 0);
      if (status === 408 || status === 429 || status >= 500) {
        onlyOpPageSize = PERFORMANCE_LIMITS.pageSize.max;
        return;
      }
      onlyOpPageSize = Math.max(onlyOpBatchFloor, onlyOpPageSize - 8);
    };

    const fetchLoaderJSON = (url, options = {}) => fetchJSON(url, {
      scheduler: requestScheduler,
      signal: requestController.signal,
      fetchOptions: options.fetchOptions,
      cacheMode: options.cacheMode || 'default',
      key: options.key || `post:${url}`,
      priority: Number.isFinite(options.priority) ? options.priority : POST_REQUEST_PRIORITY.visible,
    });

    const cachePost = (post) => {
      if (!post || !post.id) return;
      const previous = cache.get(post.id);
      const completePost = previous && previous !== post ? Object.assign(previous, post) : post;
      cache.set(post.id, completePost);
      const postNumber = +(completePost.post_number || 0);
      if (postNumber) postByNumber.set(postNumber, completePost);
    };

    const cachePosts = (posts) => (posts || []).forEach(cachePost);

    const appendMissingTopicPosts = (topicData, posts) => {
      if (!topicData || !Array.isArray(posts) || !posts.length) return false;
      if (!topicData.post_stream) topicData.post_stream = {};
      const current = Array.isArray(topicData.post_stream.posts) ? topicData.post_stream.posts : [];
      const indexesById = new Map();
      current.forEach((post, index) => {
        if (post && post.id) indexesById.set(post.id, index);
      });
      let changed = false;
      posts.forEach((post) => {
        if (!post || !post.id) return;
        const index = indexesById.get(post.id);
        if (Number.isInteger(index)) {
          const previous = current[index];
          if (previous === post) return;
          current[index] = previous ? Object.assign(previous, post) : post;
          changed = true;
          return;
        }
        indexesById.set(post.id, current.length);
        current.push(post);
        changed = true;
      });
      if (changed) topicData.post_stream.posts = current;
      return changed;
    };

    const persistFetchedPosts = (posts) => {
      if (!Array.isArray(posts) || !posts.length) return;
      const entry = TOPIC_DATA_CACHE.get(String(topicId));
      const persistedTopic = (entry && entry.topic) || topic;
      if (!persistedTopic) return;
      const changed = appendMissingTopicPosts(persistedTopic, posts);
      if (topic && topic !== persistedTopic) appendMissingTopicPosts(topic, posts);
      if (changed) setCachedTopicData(topicId, persistedTopic);
    };

    const persistViewedPostNumbers = (postNumbers) => {
      const posts = Array.from(new Set((postNumbers || []).map(Number).filter(Boolean)))
        .map((postNumber) => postByNumber.get(postNumber))
        .filter(Boolean);
      persistFetchedPosts(posts);
    };

    function normalizeTopicData(data) {
      const posts = Array.isArray(data.post_stream && data.post_stream.posts) ? data.post_stream.posts : [];
      const op = (data.details && data.details.created_by && data.details.created_by.username)
          || (posts.find((p) => p.post_number === 1) || {}).username
          || null;
      data._opUsername = op;
      return {
        posts,
        stream: (data.post_stream && data.post_stream.stream) || posts.map((p) => p.id).filter(Boolean),
      };
    }

    function primeTopicData(data) {
      const normalized = normalizeTopicData(data);
      topic = data;
      stream = normalized.stream;
      streamIndexById = new Map(stream.map((id, index) => [id, index]));
      cachePosts(normalized.posts);
      return topic;
    }

    const syncTopicCacheData = (incomingTopic) => {
      if (!incomingTopic) return;
      const incoming = normalizeTopicData(incomingTopic);
      cachePosts(incoming.posts);
      if (incomingTopic === topic) return;
      if (!topic) return;
      appendMissingTopicPosts(topic, incoming.posts);
      Object.keys(incomingTopic).forEach((key) => {
        if (key !== 'post_stream') topic[key] = incomingTopic[key];
      });
      if (incoming.stream.length >= stream.length) {
        stream = incoming.stream.slice();
        streamIndexById = new Map(stream.map((id, index) => [id, index]));
      }
    };
    stopTopicCacheSync = subscribeTopicCache(topicId, syncTopicCacheData);

    async function refreshTopicData({ prime = true, priority } = {}) {
      ensureMe();
      if (!refreshRequest) {
        refreshRequest = (async () => {
          const url = `${BASE}/t/${topicId}.json?track_visit=true&forceLoad=true`;
          const data = await fetchJSON(url, {
            scheduler: requestScheduler,
            signal: requestController.signal,
            cacheMode: 'refresh',
            fetchOptions: {
              method: 'GET',
              credentials: 'include',
              cache: 'no-store',
              headers: {
              'Accept': 'application/json, text/javascript, */*; q=0.01',
              'X-Requested-With': 'XMLHttpRequest',
              'Discourse-Present': 'true',
              'Discourse-Track-View': 'true',
              'Discourse-Track-View-Topic-Id': String(topicId),
              },
            },
            key: `topic:${topicId}:refresh`,
            priority: Number.isFinite(priority)
              ? priority
              : topic
                ? POST_REQUEST_PRIORITY.background
                : POST_REQUEST_PRIORITY.topic,
          });
          const entry = TOPIC_DATA_CACHE.get(String(topicId));
          const previousTopic = (entry && entry.topic) || topic;
          if (previousTopic && previousTopic.post_stream) {
            appendMissingTopicPosts(data, previousTopic.post_stream.posts);
          }
          normalizeTopicData(data);
          setCachedTopicData(topicId, data, {
            fetchedAt: responseCacheValueStoredAt(data) || Date.now(),
            source: 'network',
          });
          return data;
        })().finally(() => { refreshRequest = null; });
      }
      const data = await refreshRequest;
      if (prime) return primeTopicData(data);
      return data;
    }

    async function init() {
      if (topic) return topic;
      await ensureMe();
      const previewTopic = getCachedTopicData(topicId);
      const storedTopic = await getStoredTopicSnapshot(topicId);
      const cachedTopic = storedTopic || previewTopic;
      const cacheEntry = TOPIC_DATA_CACHE.get(String(topicId));
      if (cachedTopic && cacheEntry) {
        initializedFromCache = true;
        primeTopicData(cachedTopic);
        const expectedPostCount = Math.max(0, Number(topic.posts_count) || 0);
        if (expectedPostCount > stream.length) {
          initializedFromCache = false;
          return refreshTopicData();
        }
        const fetchedAt = topicCacheEntryTimestamp(cacheEntry);
        if (!fetchedAt || Date.now() - fetchedAt > TOPIC_CACHE_TTL) {
          refreshTopicData({ prime: false, priority: POST_REQUEST_PRIORITY.background }).catch(() => {});
        }
        return topic;
      }
      initializedFromCache = false;
      return refreshTopicData();
    }

    async function next(options = {}) {
      const onlyOpScan = options.onlyOp === true;
      const position = onlyOpScan ? onlyOpCursor : cursor;
      if (position >= stream.length) return { posts: [], done: true };
      const batchSize = onlyOpScan ? onlyOpPageSize : pageSize;
      const slice = stream.slice(position, position + batchSize);
      const resetFailures = () => {
        if (onlyOpScan) onlyOpFailStreak = 0;
        else failStreak = 0;
      };
      const bumpFailures = () => onlyOpScan ? ++onlyOpFailStreak : ++failStreak;
      const advance = (count, skipped = 0) => {
        if (onlyOpScan) {
          onlyOpCursor += count;
          onlyOpSkippedCount += skipped;
          return onlyOpCursor >= stream.length;
        }
        cursor += count;
        return cursor >= stream.length;
      };
      const prepareOnlyOpPosts = (posts) => {
        if (!onlyOpScan) return posts;
        const opUsername = String(options.onlyOpUsername || '');
        if (!opUsername) return posts;
        const matches = [];
        posts.forEach((post) => {
          if (String(post && post.username || '') === opUsername) {
            matches.push(post);
            return;
          }
          if (post && post.id && cache.get(post.id) === post) cache.delete(post.id);
          const postNumber = +(post && post.post_number || 0);
          if (postNumber && postByNumber.get(postNumber) === post) postByNumber.delete(postNumber);
        });
        if (matches.length) persistFetchedPosts(matches);
        return matches;
      };
      const finishBatch = (skipped = 0, growOnlyOp = false) => {
        const done = advance(slice.length, skipped);
        resetFailures();
        const posts = prepareOnlyOpPosts(slice.map((id) => cache.get(id)).filter(Boolean));
        if (growOnlyOp && onlyOpScan) growOnlyOpBatch();
        return { posts, done };
      };
      let missing = slice.filter((id) => !cache.has(id));
      if (typeof options.onSource === 'function') {
        options.onSource(missing.length ? 'network' : 'cache', {
          cachedCount: slice.length - missing.length,
          missingCount: missing.length,
          totalCount: slice.length,
        });
      }
      let loadError = null;
      if (missing.length) {
        try {
          await loadPostsByIds(slice, {
            priority: POST_REQUEST_PRIORITY.scroll,
            persistFetchedPosts: !onlyOpScan && options.persistFetchedPosts === true,
          });
        } catch (error) {
          loadError = error;
        }
        missing = slice.filter((id) => !cache.has(id));
      }

      if (missing.length) {
        if (loadError) {
          if (onlyOpScan) adjustOnlyOpBatchAfterError(loadError);
          const status = Number(loadError.status || 0);
          if (status === 401 || status === 403) {
            return { posts: [], done: false, fatal: true, error: loadError };
          }
          if (!status || shouldStopReaderFallback(loadError)) {
            resetFailures();
            return { posts: [], done: false, retry: true, error: loadError };
          }
          if (bumpFailures() < 4) return { posts: [], done: false, retry: true, error: loadError };
          return finishBatch(missing.length);
        }
        if (onlyOpScan) onlyOpPageSize = Math.max(onlyOpBatchFloor, onlyOpPageSize - 8);
        if (bumpFailures() >= 4) {
          return finishBatch(missing.length);
        }
        return { posts: [], done: false, retry: true };
      }

      return finishBatch(0, true);
    }

    async function requestMissingPostIds(ids, priority, shouldPersist) {
      const missing = ids.filter((id) => !cache.has(id));
      const unclaimed = missing.filter((id) => !pendingPostRequests.has(id));
      if (unclaimed.length) {
        const requestIds = Array.from(new Set(unclaimed));
        const requestKey = requestIds.slice().sort((a, b) => String(a).localeCompare(String(b))).join(',');
        const qs = requestIds.map((id) => `post_ids[]=${id}`).join('&');
        const request = fetchLoaderJSON(`${BASE}/t/${topicId}/posts.json?${qs}`, {
          key: `posts:${topicId}:${requestKey}`,
          priority,
        }).then((part) => {
          cachePosts(part && part.post_stream && part.post_stream.posts);
        }).finally(() => {
          requestIds.forEach((id) => {
            if (pendingPostRequests.get(id) === request) pendingPostRequests.delete(id);
          });
        });
        requestIds.forEach((id) => pendingPostRequests.set(id, request));
      }
      const requests = Array.from(new Set(
        missing.map((id) => pendingPostRequests.get(id)).filter(Boolean)
      ));
      if (requests.length) await Promise.all(requests);
      if (shouldPersist) persistFetchedPosts(missing.map((id) => cache.get(id)).filter(Boolean));
    }

    async function loadPostsByIds(ids, options = {}) {
      const requestedIds = Array.from(new Set((ids || []).filter(Boolean)));
      let missing = requestedIds.filter((id) => !cache.has(id));
      let lastError = null;
      const priority = Number.isFinite(options.priority) ? options.priority : POST_REQUEST_PRIORITY.visible;
      const maxAttempts = Math.max(1, +(options.maxAttempts || 2));
      for (let attempt = 0; attempt < maxAttempts && missing.length; attempt++) {
        try {
          await requestMissingPostIds(missing, priority, options.persistFetchedPosts === true);
          lastError = null;
        } catch (error) {
          lastError = error;
          const status = Number(error && error.status || 0);
          const splitDepth = Math.max(0, Number(options.clientSplitDepth) || 0);
          const canSplitClientError = [400, 404, 413, 414, 422].includes(status) &&
            missing.length > 1 && splitDepth < 1;
          if (canSplitClientError) {
            const middle = Math.ceil(missing.length / 2);
            const splitOptions = { ...options, maxAttempts: 1, clientSplitDepth: splitDepth + 1 };
            const results = await Promise.allSettled([
              loadPostsByIds(missing.slice(0, middle), splitOptions),
              loadPostsByIds(missing.slice(middle), splitOptions),
            ]);
            const authFailure = results.find((result) => result.status === 'rejected' &&
              [401, 403].includes(Number(result.reason && result.reason.status || 0)));
            if (authFailure) throw authFailure.reason;
            const transientFailure = results.find((result) => result.status === 'rejected' && (
              !Number(result.reason && result.reason.status || 0) || shouldStopReaderFallback(result.reason)
            ));
            if (transientFailure) throw transientFailure.reason;
            lastError = null;
            break;
          }
          if (shouldStopReaderFallback(error) || (status >= 400 && status < 500)) break;
        }
        missing = requestedIds.filter((id) => !cache.has(id));
        if (missing.length && attempt + 1 < maxAttempts) {
          await waitForDelay(240);
        }
      }
      if (missing.length && lastError) throw lastError;
      const posts = requestedIds.map((id) => cache.get(id)).filter(Boolean);
      return posts;
    }

    function streamIndexForPostNumber(postNumber) {
      const target = +postNumber;
      const cachedPost = postByNumber.get(target);
      const cachedIndex = cachedPost && streamIndexById.get(cachedPost.id);
      if (Number.isInteger(cachedIndex)) return cachedIndex;
      return Math.min(stream.length - 1, Math.max(0, target - 1));
    }

    function advanceCursorPast(posts, targetPostNumber) {
      if (!stream.length) return;
      let maxIndex = -1;
      posts.forEach((p) => {
        const byId = streamIndexById.get(p.id);
        if (Number.isInteger(byId)) {
          maxIndex = Math.max(maxIndex, byId);
        } else if (p.post_number) {
          maxIndex = Math.max(maxIndex, Math.min(stream.length - 1, Math.max(0, +p.post_number - 1)));
        }
      });
      if (maxIndex < 0 && targetPostNumber) {
        maxIndex = Math.min(stream.length - 1, Math.max(0, +targetPostNumber - 1));
      }
      if (maxIndex >= cursor) cursor = maxIndex + 1;
    }

    async function loadRelativePosts(postNumber, direction, options = {}) {
      if (!stream.length) return [];
      const last = direction === 'last';
      const targetIndex = last ? stream.length - 1 : streamIndexForPostNumber(postNumber);
      if (last && !stream[targetIndex]) return [];
      if (direction === 'before' && targetIndex <= 0) return [];
      const start = last ? targetIndex : direction === 'before'
        ? Math.max(0, targetIndex - pageSize)
        : Math.min(stream.length, targetIndex + 1);
      const end = last ? stream.length : direction === 'before' ? targetIndex : start + pageSize;
      const posts = await loadPostsByIds(stream.slice(start, end), {
        priority: Number.isFinite(options.priority) ? options.priority :
          last ? POST_REQUEST_PRIORITY.target : POST_REQUEST_PRIORITY.scroll,
        persistFetchedPosts: !last && options.persistFetchedPosts === true,
      });
      if (last && posts.length) advanceCursorPast(posts);
      return posts;
    }

    async function loadPost(postNumber, options = {}) {
      const target = +postNumber;
      if (!target || unavailablePostNumbers.has(target)) return [];
      const around = options.scope === 'around';
      const shouldAdvance = around || options.advanceCursor !== false;
      const forceRefresh = !around && options.forceRefresh === true;
      const priority = Number.isFinite(options.priority) ? options.priority : POST_REQUEST_PRIORITY.scroll;
      const cached = around || forceRefresh ? null : postByNumber.get(target);
      if (cached) {
        if (typeof options.onSource === 'function') options.onSource('cache');
        if (shouldAdvance) advanceCursorPast([cached], target);
        return [cached];
      }
      if (typeof options.onSource === 'function') options.onSource('network');
      if (!around) {
        const highestPostNumber = Math.max(0, Number(topic && topic.highest_post_number) || 0);
        const id = (!highestPostNumber || highestPostNumber === stream.length) ? stream[target - 1] : null;
        const posts = id && !forceRefresh ? await loadPostsByIds([id], { priority }) : [];
        const hit = posts.find((post) => +post.post_number === target);
        if (hit) {
          if (shouldAdvance) advanceCursorPast([hit], target);
          return [hit];
        }
      }
      const slug = encodeURIComponent((topic && topic.slug) || 'topic');
      const urls = around
        ? [
            `${BASE}/t/${slug}/${topicId}/${target}.json`,
            `${BASE}/t/${slug}/${topicId}.json?post_number=${target}`,
            `${BASE}/t/${topicId}.json?post_number=${target}`,
            `${BASE}/posts/by_number/${topicId}/${target}.json`,
          ]
        : [
            `${BASE}/posts/by_number/${topicId}/${target}.json`,
            `${BASE}/t/${slug}/${topicId}/${target}.json`,
            `${BASE}/t/${topicId}.json?post_number=${target}`,
          ];
      let fallbackPosts = [];
      for (const url of urls) {
        try {
          const payload = await fetchLoaderJSON(url, {
            key: `${forceRefresh ? 'force-' : ''}${around ? 'around' : 'single'}:${topicId}:${target}:${url}`,
            priority,
            fetchOptions: forceRefresh ? { cache: 'no-store' } : {},
            cacheMode: forceRefresh ? 'refresh' : 'default',
          });
          const fetched = postsFromPayload(payload).filter((p) => p && p.id && p.post_number);
          cachePosts(fetched);
          const found = fetched.find((p) => +p.post_number === target);
          if (found) {
            if (shouldAdvance) advanceCursorPast(around ? fetched : [found], target);
            return around ? fetched : [found];
          }
          if (around && fetched.length && !fallbackPosts.length) fallbackPosts = fetched;
        } catch (error) {
          const status = Number(error && error.status || 0);
          if (!around && (status === 404 || status === 410) && url.includes('/posts/by_number/')) {
            unavailablePostNumbers.add(target);
            return [];
          }
          if (shouldStopReaderFallback(error)) throw error;
        }
      }
      if (around && stream.length) {
        const start = Math.max(0, Math.min(stream.length - pageSize, target - 1 - Math.floor(pageSize / 2)));
        const ids = stream.slice(start, start + pageSize);
        if (ids.length) {
          try {
            const posts = await loadPostsByIds(ids, { priority });
            if (posts.length) {
              advanceCursorPast(posts, target);
              return posts;
            }
          } catch (error) {
            if (shouldStopReaderFallback(error)) throw error;
          }
        }
      }
      if (around && fallbackPosts.length) advanceCursorPast(fallbackPosts, target);
      return around ? fallbackPosts : [];
    }

    return {
      init, next, loadPostsByIds, loadPost,
      loadBeforePost: (postNumber, options) => loadRelativePosts(postNumber, 'before', options),
      loadAfterPost: (postNumber, options) => loadRelativePosts(postNumber, 'after', options),
      loadLastPost: (options) => loadRelativePosts(0, 'last', options),
      refreshTopicData,
      persistViewedPostNumbers, persistFetchedPosts,
      destroy() {
        stopTopicCacheSync();
        stopTopicCacheSync = () => {};
        requestController.abort();
        stream.length = 0;
        cache.clear();
        postByNumber.clear();
        unavailablePostNumbers.clear();
        pendingPostRequests.clear();
        streamIndexById.clear();
        topic = null;
        refreshRequest = null;
      },
      get topic() { return topic; },
      get cachedPosts() { return Array.from(cache.values()); },
      get initializedFromCache() { return initializedFromCache; },
      get loadDone() { return cursor >= stream.length; },
      get scanDone() { return onlyOpCursor >= stream.length; },
      get scanCursor() { return onlyOpCursor; },
      get scanSkippedCount() { return onlyOpSkippedCount; },
      get scanBatchSize() { return onlyOpPageSize; },
      get streamLength() { return stream.length; },
    };
  }

  /* ============ 6. 楼层归位 ============ */
  function streamItemParticipatesInZebra(item) {
    return !!(item && item.node) &&
      !item.zebraExcluded &&
      !item.node.classList.contains('ldp-nested-collapsed') &&
      !item.node.classList.contains('ldp-nested-preview');
  }

  function reindexStreamItems(ctx, start = 0) {
    const items = ctx && ctx.streamItems;
    if (!items || !items.length) return;
    const from = Math.max(0, Math.min(items.length - 1, +start || 0));
    let zebraIndex = from > 0 ? +(items[from - 1].zebraCountAfter || 0) : 0;
    for (let index = from; index < items.length; index++) {
      const item = items[index];
      const participates = streamItemParticipatesInZebra(item);
      item.index = index;
      item.zebraIndex = participates ? zebraIndex++ : -1;
      item.zebraCountAfter = zebraIndex;
    }
  }

  function insertStreamPost(ctx, node, postNumber, options = {}) {
    const current = +postNumber;
    if (!current || ctx.streamItemMap.has(current)) return;
    let low = 0;
    let high = ctx.streamItems.length;
    const compare = (item) => {
      if (!ctx.isPostVoting) return item.postNumber - current;
      if (item.postNumber === 1 || current === 1) return item.postNumber === current ? 0 : (item.postNumber === 1 ? -1 : 1);
      const left = +(item.node && item.node._ldpPostData && item.node._ldpPostData.post_voting_vote_count || 0);
      const right = +(node._ldpPostData && node._ldpPostData.post_voting_vote_count || 0);
      return right - left || item.postNumber - current;
    };
    while (low < high) {
      const mid = Math.floor((low + high) / 2);
      if (compare(ctx.streamItems[mid]) < 0) low = mid + 1;
      else high = mid;
    }
    const estimatedHeight = Math.max(
      STREAM_ESTIMATED_HEIGHT,
      postContentPlaceholderHeight(node._ldpPostData) + 72
    );
    if (ctx.streamMountedNodes.size && ctx.streamWindowEnd > ctx.streamWindowStart) {
      if (low < ctx.streamWindowStart) {
        ctx.streamWindowStart++;
        ctx.streamWindowEnd++;
      } else if (low < ctx.streamWindowEnd) {
        ctx.streamWindowEnd++;
      }
    }
    const item = {
      postNumber: current,
      username: String((node._ldpPostData && node._ldpPostData.username) || node.dataset.username || ''),
      node,
      zebraExcluded: options.zebraExcluded === true,
      height: estimatedHeight,
      index: low,
    };
    ctx.streamItems.splice(low, 0, item);
    ctx.streamItemMap.set(current, item);
    if (options.deferSync) {
      ctx.streamPendingReindexFrom = Number.isInteger(ctx.streamPendingReindexFrom)
        ? Math.min(ctx.streamPendingReindexFrom, low)
        : low;
    } else {
      reindexStreamItems(ctx, low);
    }
    if (ctx.onlyOp) invalidateStreamLayout(ctx);
    else markStreamPrefixDirty(ctx, low);
    ctx.streamNeedsRepair = true;
    ensureStreamScaffold(ctx);
    if (!options.deferSync) scheduleStreamWindowSync(ctx);
  }

  function flushStreamPostBatch(ctx, syncNow = false, preserveViewportAnchor = false) {
    if (!ctx || !Number.isInteger(ctx.streamPendingReindexFrom)) return;
    const dirtyFrom = ctx.streamPendingReindexFrom;
    reindexStreamItems(ctx, dirtyFrom);
    ctx.streamPendingReindexFrom = null;
    if (ctx.onlyOp) invalidateStreamLayout(ctx);
    else markStreamPrefixDirty(ctx, dirtyFrom);
    if (syncNow) {
      const keepMountedWindow = preserveViewportAnchor && ctx.streamViewportAnchor &&
        ctx.streamMountedNodes.size > 0 && ctx.streamWindowEnd > ctx.streamWindowStart;
      if (keepMountedWindow) {
        if (ctx.streamWindowFrame) cancelAnimationFrame(ctx.streamWindowFrame);
        ctx.streamWindowFrame = 0;
        // Prepending changes every item index before scrollTop can be corrected.
        // Keep the anchored DOM mounted, restore it, then calculate the new window.
        mountStreamRange(ctx, ctx.streamWindowStart, ctx.streamWindowEnd);
        syncStreamWindow(ctx);
      } else {
        flushStreamWindow(ctx);
      }
      if (ctx.timeline) ctx.timeline.update();
    } else {
      scheduleStreamWindowSync(ctx);
    }
  }

  function refreshStreamZebra(ctx, nodes = null) {
    if (!ctx || !ctx.commentsEl) return;
    if (ctx.onlyOp) streamLayoutItems(ctx);
    const targets = nodes || ctx.commentsEl.children;
    for (const node of targets) {
      if (!node.classList.contains('ldp-post')) continue;
      const item = ctx.streamItemMap && ctx.streamItemMap.get(streamPostNumber(node));
      const zebraIndex = item ? (ctx.onlyOp ? item.layoutZebraIndex : item.zebraIndex) : -1;
      node.classList.toggle('ldp-zebra-alt', zebraIndex >= 0 && zebraIndex % 2 === 1);
    }
  }

  function applyNestedReplyDisplayPreference(ctx) {
    if (!ctx || !Array.isArray(ctx.streamItems)) return;
    const collapseChildren = PREFS.expandNestedRepliesByDefault !== true;
    const expandLeaf = PREFS.expandLeafNestedReplies === true;
    let reindexFrom = null;
    ctx.streamItems.forEach((item, index) => {
      const node = item && item.node;
      if (!node) return;
      const keepOnlyOpExpanded = !!(ctx.onlyOp && String(item.username || '') === String(ctx.op || ''));
      if (+(node.dataset.childReplyTotal || 0) > 0) {
        setChildRepliesCollapsed(node, keepOnlyOpExpanded ? false : collapseChildren);
      }
      const post = node._ldpPostData;
      const isLeafNestedReply = !!(post && node.classList.contains('ldp-reply-collapsible') &&
        !post.hidden && !(+post.reply_count > 0));
      if (!isLeafNestedReply) return;
      const repliesToTopicStarter = +(post.reply_to_post_number || node.dataset.replyToPostNumber || 0) === 1;
      const collapsed = !expandLeaf && !keepOnlyOpExpanded && !repliesToTopicStarter;
      setNestedReplyCollapsed(node, collapsed, { deferZebraSync: true });
      if (item.zebraExcluded === collapsed) return;
      item.zebraExcluded = collapsed;
      reindexFrom = reindexFrom == null ? index : Math.min(reindexFrom, index);
    });
    if (reindexFrom == null) return;
    reindexStreamItems(ctx, reindexFrom);
    if (ctx.onlyOp) invalidateStreamLayout(ctx);
    else markStreamPrefixDirty(ctx, reindexFrom);
    refreshStreamZebra(ctx);
    scheduleStreamWindowSync(ctx);
  }

  function findReplyListParent(postNumber, ctx) {
    const num = +postNumber;
    if (!num || !ctx) return null;
    const streamNode = getStreamPostNode(ctx, num);
    if (streamNode && streamNode.isConnected) return streamNode;
    return (ctx.commentsEl && ctx.commentsEl.querySelector(`:scope > .ldp-post[data-post-number="${num}"]`)) ||
        null;
  }

  function rememberLatestReplyTime(ctx, post, options = {}) {
    const createdAt = String((post && post.created_at) || '');
    const timestamp = Date.parse(createdAt);
    if (!ctx || !Number.isFinite(timestamp)) return;
    if (!options.force && timestamp <= +(ctx.latestReplyTimestamp || 0)) return;
    ctx.latestReplyAt = createdAt;
    ctx.latestReplyTimestamp = timestamp;
    if (ctx.timeline) ctx.timeline.update();
  }

  function rememberPostData(ctx, post, parentHint = 0) {
    const postNumber = +(post && post.post_number || 0);
    if (!ctx || !postNumber) return 0;
    const knownParentNumber = +(ctx.replyParentByPost && ctx.replyParentByPost.get(postNumber) || 0);
    const parentNumber = +(post.reply_to_post_number || parentHint || knownParentNumber || 0);
    if (!parentNumber) return 0;
    if (!post.reply_to_post_number) post.reply_to_post_number = parentNumber;
    if (ctx.replyParentByPost) ctx.replyParentByPost.set(postNumber, parentNumber);
    let replies = ctx.directRepliesByParent.get(parentNumber);
    if (!replies) {
      replies = new Map();
      ctx.directRepliesByParent.set(parentNumber, replies);
    }
    replies.set(postNumber, post);
    return parentNumber;
  }

  function attachPostBatch(posts, ctx, options = {}) {
    const batch = Array.isArray(posts) ? posts : [];
    if (!batch.length) return [];
    const batchOptions = { ...options, deferStreamSync: true };
    const nodes = batch.map((post) => attachPost(post, ctx, batchOptions)).filter(Boolean);
    syncKnownBoostIdentities(ctx, batch.map((post) => post && post.username));
    flushStreamPostBatch(
      ctx,
      options.syncStreamNow === true,
      options.preserveViewportAnchor === true,
    );
    return nodes;
  }

  function attachPost(p, ctx, options = {}) {
    const rememberedParentNum = rememberPostData(ctx, p);
    rememberLatestReplyTime(ctx, p);
    const fromNestedList = !!options.nestedList;
    const parentNum = +(p.reply_to_post_number || rememberedParentNum || 0);
    const isNestedReply = !ctx.isPostVoting && !!parentNum;
    const renderAsReply = isNestedReply || (fromNestedList && !!parentNum);
    const preferredParentNode = options.preferredParentNode;
    const preferredParentMatches = preferredParentNode && preferredParentNode.isConnected &&
      +preferredParentNode.dataset.postNumber === +parentNum;
    const logicalParentNode = fromNestedList && parentNum
      ? (preferredParentMatches ? preferredParentNode : findReplyListParent(parentNum, ctx))
      : null;
    // A nested-list request always belongs to the requested post. Do not walk
    // that post's own parent chain: A -> B -> A conversations would otherwise
    // be reattached to an ancestor and create a visual reply cycle.
    const parentNode = fromNestedList ? logicalParentNode : null;
    if (fromNestedList) {
      const parentChildren = parentNode && parentNode.querySelector(':scope > .ldp-children');
      const existingNode = parentChildren && parentChildren.querySelector(
        `:scope > .ldp-post[data-post-number="${+p.post_number}"]`
      );
      if (existingNode) return existingNode;
      const node = renderPost(p, renderAsReply, ctx, {
        forceExpanded: true,
        nestedPreview: true,
        showParentJump: false,
      });
      if (parentNode) {
        if (!options.deferNestedSync) parentChildren.appendChild(node);
        bindPostMediaLayoutSync(node, ctx);
        const streamNode = ctx.streamNodeMap.get(p.post_number);
        if (streamNode) {
          const streamIsNestedReply = +(p.reply_to_post_number || 0) > 0;
          const repliesToTopicStarter = +(p.reply_to_post_number || 0) === 1;
          const keepJumpTargetExpanded = streamNode.dataset.ldpJumpExpanded === '1';
          if (streamIsNestedReply) {
            ensureStreamNestedReplyPresentation(streamNode, p.reply_to_post_number);
          }
          if (streamNode._ldpPostData?.hidden) {
            setNestedReplyCollapsed(streamNode, true);
          } else if (repliesToTopicStarter || !streamIsNestedReply || p.reply_count > 0) {
            setNestedReplyCollapsed(streamNode, false);
            if (p.reply_count > 0) {
              ctx.repliesIO.observe(streamNode);
            }
          } else {
            setNestedReplyCollapsed(streamNode, !keepJumpTargetExpanded);
          }
        }
        if (!options.deferNestedSync) syncChildControls(parentNode);
      }
      if (parentNode) ctx.tracker.observe(node);
      return node;
    }

    if (ctx.streamNodeMap.has(+p.post_number)) return ctx.streamNodeMap.get(+p.post_number) || null;

    const hiddenStreamPost = !!p.hidden;
    const collapsedStreamReply = hiddenStreamPost || !!(isNestedReply && parentNum !== 1 && !(p.reply_count > 0) &&
      PREFS.expandLeafNestedReplies !== true);
    const node = renderPost(p, renderAsReply, ctx, {
      forceCollapsed: collapsedStreamReply,
      showParentJump: isNestedReply,
      deferContent: true,
    });
    insertStreamPost(ctx, node, p.post_number, {
      deferSync: !!options.deferStreamSync,
      zebraExcluded: hiddenStreamPost || collapsedStreamReply,
    });
    bindPostMediaLayoutSync(node, ctx);
    ctx.streamNodeMap.set(+p.post_number, node);
    ctx.tracker.observe(node);
    if (ctx.queueViewportTracker) ctx.queueViewportTracker.observe(node);
    if (+p.post_number === 1) syncCommentsHeaderPlacement(ctx);
    return node;
  }

  let threadGroupGradientSerial = 0;

  function findParentPreviewLine(post) {
    const line = post && post.previousElementSibling;
    return line && line.classList.contains('ldp-floor-preview-link') ? line : null;
  }

  function clearCombinedParentPreviewLine(post) {
    const line = findParentPreviewLine(post);
    if (line) {
      line.classList.remove('ldp-floor-preview-link-grouped');
      line.querySelector(':scope > .ldp-thread-group-svg')?.remove();
    }
    if (post) {
      post.querySelector(':scope > .ldp-thread-group-svg')?.remove();
      post.classList.remove('ldp-parent-preview-linked');
    }
  }

  function syncGroupedParentPreviewLine(line, parent, posts) {
    const preview = line && line.previousElementSibling;
    if (!line || !line.classList.contains('open') || !preview || !preview.classList.contains('ldp-floor-preview')) return false;
    const parentAvatar = parent && parent.querySelector(':scope > .ldp-post-head .ldp-avatar');
    const childAvatars = posts.map((post) => post.querySelector(':scope > .ldp-post-head .ldp-avatar'));
    const previewAvatar = preview.querySelector(':scope > .ldp-post-head .ldp-avatar');
    if (!parentAvatar || !previewAvatar || childAvatars.some((avatar) => !avatar)) return false;
    const layerRect = parent.getBoundingClientRect();
    const previewRect = preview.getBoundingClientRect();
    const previewAvatarRect = previewAvatar.getBoundingClientRect();
    const points = [{
      x: previewRect.left - layerRect.left,
      y: previewAvatarRect.top + previewAvatarRect.height / 2 - layerRect.top,
    }];
    [parentAvatar, ...childAvatars].forEach((avatar) => {
      const rect = avatar.getBoundingClientRect();
      points.push({
        x: rect.left - layerRect.left,
        y: rect.top + rect.height / 2 - layerRect.top,
      });
    });
    if (points.some((point) => !Number.isFinite(point.x) || !Number.isFinite(point.y))) return false;
    const lineStyle = getComputedStyle(line);
    const radius = normalizeReplyLineRadius(parseFloat(lineStyle.getPropertyValue('--ldp-reply-line-radius')));
    const lineWidth = normalizeLineWidth(parseFloat(lineStyle.getPropertyValue('--ldp-reply-line-width')), REPLY_LINE_WIDTH_DEFAULT);
    const linePadding = Math.ceil(lineWidth / 2) + 1;
    const branchGap = 5;
    const axisX = Math.min(...points.map((point) => point.x)) - radius;
    const minX = Math.floor(axisX - linePadding);
    const maxX = Math.ceil(Math.max(...points.map((point) => point.x)) + linePadding);
    const minY = Math.floor(points[0].y - linePadding);
    const maxY = Math.ceil(points[points.length - 1].y + linePadding);
    const width = Math.max(1, maxX - minX);
    const height = Math.max(1, maxY - minY);
    const localX = (value) => Math.round(value - minX);
    const localY = (value) => Math.round(value - minY);
    const trunkX = localX(axisX);
    const topY = localY(points[0].y);
    const bottomY = localY(points[points.length - 1].y - radius);
    const curveEndX = localX(axisX + radius);
    const topCurveStartY = localY(points[0].y + radius);
    const solidPathParts = [
      `M ${trunkX} ${topCurveStartY} V ${bottomY}`,
      `M ${trunkX} ${topCurveStartY} Q ${trunkX} ${topY} ${curveEndX} ${topY}`,
    ];
    const topBranchEndX = localX(points[0].x - branchGap);
    const branchPathParts = [{
      d: `M ${curveEndX} ${topY} H ${topBranchEndX}`,
      reverse: topBranchEndX < curveEndX,
      startX: curveEndX,
      endX: topBranchEndX,
      y: topY,
    }];
    points.slice(1).forEach((point) => {
      const y = localY(point.y);
      solidPathParts.push(`M ${trunkX} ${localY(point.y - radius)} Q ${trunkX} ${y} ${curveEndX} ${y}`);
      const branchEndX = localX(point.x - branchGap);
      branchPathParts.push({
        d: `M ${curveEndX} ${y} H ${branchEndX}`,
        reverse: branchEndX < curveEndX,
        startX: curveEndX,
        endX: branchEndX,
        y,
      });
    });
    const pathParts = [{ d: solidPathParts.join(' '), branch: false, reverse: false },
      ...branchPathParts.map((part) => ({ ...part, branch: true }))];
    let svg = parent.querySelector(':scope > .ldp-thread-group-svg');
    if (!svg) {
      svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
      svg.classList.add('ldp-thread-group-svg');
      svg.setAttribute('aria-hidden', 'true');
      parent.appendChild(svg);
    }
    svg.style.left = `${minX}px`;
    svg.style.top = `${minY}px`;
    svg.style.width = `${width}px`;
    svg.style.height = `${height}px`;
    svg.setAttribute('viewBox', `0 0 ${width} ${height}`);
    let defs = svg.querySelector(':scope > .ldp-thread-group-defs');
    if (!defs) {
      defs = document.createElementNS('http://www.w3.org/2000/svg', 'defs');
      defs.classList.add('ldp-thread-group-defs');
      svg.insertBefore(defs, svg.firstChild);
    }
    const gradients = Array.from(defs.querySelectorAll(':scope > .ldp-thread-group-gradient'));
    while (gradients.length < branchPathParts.length) {
      const gradient = document.createElementNS('http://www.w3.org/2000/svg', 'linearGradient');
      gradient.classList.add('ldp-thread-group-gradient');
      gradient.id = `ldp-thread-group-gradient-${++threadGroupGradientSerial}`;
      gradient.setAttribute('gradientUnits', 'userSpaceOnUse');
      [0, 1, 1].forEach((offset, index) => {
        const stop = document.createElementNS('http://www.w3.org/2000/svg', 'stop');
        stop.setAttribute('offset', String(offset));
        stop.setAttribute('stop-color', 'currentColor');
        stop.setAttribute('stop-opacity', index === 2 ? '0' : '1');
        gradient.appendChild(stop);
      });
      defs.appendChild(gradient);
      gradients.push(gradient);
    }
    while (gradients.length > branchPathParts.length) gradients.pop().remove();
    const paths = Array.from(svg.querySelectorAll(':scope > .ldp-thread-group-path'));
    while (paths.length < pathParts.length) {
      const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
      path.classList.add('ldp-thread-group-path');
      svg.appendChild(path);
      paths.push(path);
    }
    while (paths.length > pathParts.length) paths.pop().remove();
    let branchGradientIndex = 0;
    paths.forEach((path, index) => {
      const part = pathParts[index];
      path.classList.toggle('ldp-thread-group-branch', part.branch);
      path.classList.toggle('ldp-thread-group-branch-reverse', part.reverse);
      path.setAttribute('d', part.d);
      if (!part.branch) {
        path.style.removeProperty('stroke');
        return;
      }
      const gradient = gradients[branchGradientIndex++];
      const branchLength = Math.max(1, Math.abs(part.endX - part.startX));
      const fadeStart = Math.max(0, 1 - 12 / branchLength);
      gradient.setAttribute('x1', String(part.startX));
      gradient.setAttribute('x2', String(part.endX));
      gradient.setAttribute('y1', String(part.y));
      gradient.setAttribute('y2', String(part.y));
      gradient.children[1].setAttribute('offset', String(fadeStart));
      path.style.stroke = `url(#${gradient.id})`;
    });
    line.classList.add('ldp-floor-preview-link-grouped');
    parent.classList.add('ldp-parent-preview-linked');
    return true;
  }

  function syncNestedReplyBranches(children) {
    const posts = Array.from(children.children).filter((node) => node.classList.contains('ldp-post'));
    const parent = children.closest('.ldp-post');
    const parentAvatar = parent && parent.querySelector(':scope > .ldp-post-head .ldp-avatar');
    const railToggle = children.querySelector(':scope > .ldp-nested-rail-toggle');
    const branchToggle = children.querySelector(':scope > .ldp-nested-branch-toggle');
    if (!parent || !parentAvatar || !posts.length || !children.isConnected) {
      if (parent) {
        parent.classList.remove('ldp-nested-branches-ready');
        clearCombinedParentPreviewLine(parent);
      }
      return;
    }
    const branchGap = 5;
    let branchAxisX = null;
    let branchMetrics = [];
    let railTop = 0;
    let branchCanvasWidth = 0;
    let parentBranchWidth = 0;
    if (parentAvatar && posts.length) {
      const childrenRect = children.getBoundingClientRect();
      const avatarRect = parentAvatar.getBoundingClientRect();
      if (!childrenRect.width || !avatarRect.width || !avatarRect.height) {
        parent.classList.remove('ldp-nested-branches-ready');
        clearCombinedParentPreviewLine(parent);
        return;
      }
      let axisX = Math.round(avatarRect.left - childrenRect.left - 15);
      let dropAnchorY = avatarRect.top + avatarRect.height / 2;
      const parentLine = findParentPreviewLine(parent);
      const parentAxisX = parentLine && parseFloat(parentLine.style.getPropertyValue('--ldp-parent-axis-left'));
      const parentPreviewLinked = !!parentLine && parentLine.classList.contains('open') && Number.isFinite(parentAxisX);
      if (parentPreviewLinked) {
        axisX = Math.round(parentLine.getBoundingClientRect().left + parentAxisX - childrenRect.left);
        dropAnchorY = avatarRect.top + avatarRect.height / 2;
      }
      const firstChildAvatar = posts[0] && posts[0].querySelector(':scope > .ldp-post-head .ldp-avatar');
      const firstChildX = firstChildAvatar ? Math.round(firstChildAvatar.getBoundingClientRect().left - childrenRect.left) : 18;
      const firstBranchWidth = Math.max(0, firstChildX - axisX - branchGap);
      const parentHeadWidth = Math.max(0, avatarRect.left - childrenRect.left - axisX - branchGap);
      branchCanvasWidth = Math.max(1, Math.ceil(childrenRect.width));
      parentBranchWidth = parentHeadWidth;
      const drop = Math.max(0, Math.round(childrenRect.top - dropAnchorY));
      railTop = -drop;
      branchAxisX = axisX;
      branchMetrics = posts.map((post) => {
        const childAvatar = post.querySelector(':scope > .ldp-post-head .ldp-avatar');
        if (!childAvatar) return null;
        const childAvatarRect = childAvatar.getBoundingClientRect();
        const postRect = post.getBoundingClientRect();
        return {
          branchY: Math.max(0, Math.round(childAvatarRect.top + childAvatarRect.height / 2 - postRect.top)),
          branchWidth: Math.max(0, Math.round(childAvatarRect.left - childrenRect.left) - branchAxisX - branchGap),
          railY: Math.max(0, Math.round(childAvatarRect.top + childAvatarRect.height / 2 - childrenRect.top)),
        };
      });
      const groupedReady = parentPreviewLinked && branchMetrics.length === posts.length && branchMetrics.every(Boolean) &&
        syncGroupedParentPreviewLine(parentLine, parent, posts);
      if (!groupedReady) clearCombinedParentPreviewLine(parent);
      children.style.setProperty('--ldp-nested-axis-left', `${axisX}px`);
      children.style.setProperty('--ldp-nested-branch-width', `${firstBranchWidth}px`);
      children.style.setProperty('--ldp-nested-parent-drop', `${drop}px`);
      children.style.setProperty('--ldp-nested-parent-head-width', `${parentHeadWidth}px`);
    } else {
      children.style.removeProperty('--ldp-nested-axis-left');
      children.style.removeProperty('--ldp-nested-branch-width');
      children.style.removeProperty('--ldp-nested-parent-drop');
      children.style.removeProperty('--ldp-nested-parent-head-width');
    }
    const firstBranchMetric = branchMetrics.find(Boolean);
    const lastBranchMetric = branchMetrics[branchMetrics.length - 1];
    if (railToggle && branchAxisX !== null && firstBranchMetric && lastBranchMetric) {
      railToggle.style.left = `${branchAxisX - 10}px`;
      railToggle.style.top = `${railTop}px`;
      railToggle.style.height = `${Math.max(24, lastBranchMetric.railY - 15 - railTop)}px`;
    } else if (railToggle) {
      railToggle.style.removeProperty('left');
      railToggle.style.removeProperty('top');
      railToggle.style.removeProperty('height');
    }
    if (branchToggle && branchAxisX !== null && lastBranchMetric && branchCanvasWidth) {
      const radius = normalizeReplyLineRadius(
        parseFloat(getComputedStyle(children).getPropertyValue('--ldp-reply-line-radius'))
      );
      const branchBottom = Math.max(railTop + 1, lastBranchMetric.railY + 10);
      const branchHeight = branchBottom - railTop;
      const pathParts = [
        `M ${branchAxisX} ${railTop} H ${branchAxisX + parentBranchWidth}`,
        `M ${branchAxisX} ${railTop} V ${Math.max(railTop, lastBranchMetric.railY - radius)}`,
      ];
      branchMetrics.forEach((metric) => {
        if (!metric) return;
        pathParts.push(`M ${branchAxisX} ${metric.railY - radius} Q ${branchAxisX} ${metric.railY} ${branchAxisX + radius} ${metric.railY} H ${branchAxisX + metric.branchWidth}`);
      });
      branchToggle.style.left = '0px';
      branchToggle.style.top = `${railTop}px`;
      branchToggle.style.width = `${branchCanvasWidth}px`;
      branchToggle.style.height = `${branchHeight}px`;
      branchToggle.setAttribute('viewBox', `0 ${railTop} ${branchCanvasWidth} ${branchHeight}`);
      branchToggle.querySelector(':scope > .ldp-nested-branch-hit-path')?.setAttribute('d', pathParts.join(' '));
    } else if (branchToggle) {
      branchToggle.removeAttribute('viewBox');
      branchToggle.style.removeProperty('left');
      branchToggle.style.removeProperty('top');
      branchToggle.style.removeProperty('width');
      branchToggle.style.removeProperty('height');
      branchToggle.querySelector(':scope > .ldp-nested-branch-hit-path')?.removeAttribute('d');
    }
    posts.forEach((post, index) => {
      if (branchAxisX === null) {
        post.style.removeProperty('--ldp-nested-branch-y');
        post.style.removeProperty('--ldp-nested-branch-width');
      } else {
        const metric = branchMetrics[index];
        if (metric) {
          post.style.setProperty('--ldp-nested-branch-y', `${metric.branchY}px`);
          post.style.setProperty('--ldp-nested-branch-width', `${metric.branchWidth}px`);
        } else {
          post.style.removeProperty('--ldp-nested-branch-y');
          post.style.removeProperty('--ldp-nested-branch-width');
        }
      }
      post.classList.toggle('ldp-nested-branch-last', index === posts.length - 1);
      post.classList.toggle('ldp-nested-branch-single', posts.length === 1);
    });
    parent.classList.toggle('ldp-nested-branches-ready', branchMetrics.length === posts.length && branchMetrics.every(Boolean));
  }

  const nestedBranchSyncFrames = new WeakMap();

  function scheduleNestedBranchSync(post, ctx) {
    if (!post || !post.isConnected) return;
    const parentNum = +(post.dataset.replyToPostNumber || 0);
    const parent = parentNum && ctx && ctx.streamNodeMap && ctx.streamNodeMap.get(parentNum);
    if (nestedBranchSyncFrames.has(post)) return;
    const run = () => {
      if (!post.isConnected) {
        nestedBranchSyncFrames.delete(post);
        return;
      }
      if (streamScrollIsActive(ctx, 100)) {
        nestedBranchSyncFrames.set(post, setTimeout(run, 110));
        return;
      }
      nestedBranchSyncFrames.delete(post);
      syncChildControls(post);
      if (parent) syncChildControls(parent);
    };
    const handle = streamScrollIsActive(ctx, 100)
      ? setTimeout(run, 110)
      : requestAnimationFrame(run);
    nestedBranchSyncFrames.set(post, handle);
  }

  function syncReaderSvgSymbols(content) {
    if (!content || !content.isConnected) return;
    const root = content.getRootNode();
    if (!root || !root.host || typeof root.getElementById !== 'function') return;
    const missing = new Map();
    content.querySelectorAll('svg use').forEach((use) => {
      const href = use.getAttribute('href') || use.getAttribute('xlink:href') || '';
      if (!href.startsWith('#')) return;
      const id = href.slice(1);
      if (!id || root.getElementById(id) || missing.has(id)) return;
      const source = document.getElementById(id);
      if (source) missing.set(id, source);
    });
    const pending = Array.from(missing.entries());
    for (let index = 0; index < pending.length; index++) {
      const source = pending[index][1];
      [source, ...source.querySelectorAll('*')].forEach((node) => {
        Array.from(node.attributes || []).forEach((attribute) => {
          const references = [];
          if ((attribute.name === 'href' || attribute.name === 'xlink:href') && attribute.value.startsWith('#')) {
            references.push(attribute.value.slice(1));
          }
          for (const match of attribute.value.matchAll(/url\(\s*["']?#([^\s"')]+)["']?\s*\)/g)) references.push(match[1]);
          references.forEach((id) => {
            if (!id || root.getElementById(id) || missing.has(id)) return;
            const dependency = document.getElementById(id);
            if (!dependency) return;
            missing.set(id, dependency);
            pending.push([id, dependency]);
          });
        });
      });
    }
    if (!missing.size) return;
    let sprite = root.querySelector(':scope > svg[data-ldp-svg-sprite]');
    if (!sprite) {
      sprite = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
      sprite.dataset.ldpSvgSprite = '1';
      sprite.setAttribute('aria-hidden', 'true');
      sprite.style.cssText = 'position:absolute;width:0;height:0;overflow:hidden;pointer-events:none';
      sprite.appendChild(document.createElementNS('http://www.w3.org/2000/svg', 'defs'));
      root.prepend(sprite);
    }
    const defs = sprite.querySelector('defs');
    missing.forEach((source) => defs.appendChild(source.cloneNode(true)));
  }

  function retryableReaderImageUrl(source) {
    try {
      const url = new URL(String(source || ''), location.href);
      url.searchParams.set('_ldp_retry', String(Date.now()));
      return url.href;
    } catch (error) {
      return String(source || '');
    }
  }

  function showReaderImageRetry(img, post, ctx) {
    if (!img || img.classList.contains('emoji')) return;
    let button = img._ldpImageRetryButton;
    if (!button || !button.isConnected) {
      button = document.createElement('button');
      button.type = 'button';
      button.className = 'ldp-image-retry';
      button.innerHTML = `${icon('rotateCcw')}<span>重试图片</span>`;
      button.addEventListener('click', (event) => {
        event.preventDefault();
        event.stopPropagation();
        if (button.disabled) return;
        const source = String(img.dataset.ldpRetrySource || img.currentSrc || img.src || '');
        if (!source) return;
        button.disabled = true;
        button.setAttribute('aria-busy', 'true');
        button.querySelector('span').textContent = '正在重试…';
        const retryUrl = retryableReaderImageUrl(source);
        img.loading = 'eager';
        img.srcset = retryUrl;
        img.src = retryUrl;
        scheduleNestedBranchSync(post, ctx);
      });
      const link = img.closest('a');
      if (link && post.contains(link)) link.insertAdjacentElement('afterend', button);
      else img.insertAdjacentElement('afterend', button);
      img._ldpImageRetryButton = button;
    }
    button.disabled = false;
    button.setAttribute('aria-busy', 'false');
    button.querySelector('span').textContent = '重试图片';
  }

  function clearReaderImageRetry(img) {
    const button = img && img._ldpImageRetryButton;
    if (button) button.remove();
    if (img) img._ldpImageRetryButton = null;
  }

  function bindPostMediaLayoutSync(post, ctx) {
    const content = post.querySelector(':scope > .ldp-content');
    if (!content) return;
    syncReaderSvgSymbols(post);
    content.querySelectorAll('iframe').forEach((frame) => {
      frame.loading = 'lazy';
    });
    content.querySelectorAll('video').forEach((video) => {
      if (!video.hasAttribute('preload')) video.preload = 'metadata';
    });
    activateReaderMedia(content);
    content.querySelectorAll('img').forEach((img) => {
      if (img.dataset.ldpLayoutSyncBound === '1') return;
      img.dataset.ldpLayoutSyncBound = '1';
      if (!img.classList.contains('emoji')) {
        img.loading = 'lazy';
        img.decoding = 'async';
        if (!img.dataset.ldpRetrySource) {
          img.dataset.ldpRetrySource = absoluteImageUrl(img.currentSrc || img.src || img.getAttribute('src') || '');
        }
      }
      const onLoad = () => {
        clearReaderImageRetry(img);
        scheduleNestedBranchSync(post, ctx);
      };
      const onError = () => {
        showReaderImageRetry(img, post, ctx);
        scheduleNestedBranchSync(post, ctx);
      };
      img.addEventListener('load', onLoad);
      img.addEventListener('error', onError);
      if (img.complete) {
        if (img.naturalWidth > 0) onLoad();
        else onError();
      }
    });
  }

  function syncChildControls(post) {
    const children = post && post.querySelector(':scope > .ldp-children');
    const btn = post && post.querySelector(':scope > .ldp-collapse-replies');
    if (!children || !btn) return;
    const collapsed = post.classList.contains('ldp-children-collapsed');
    let renderedCount = 0;
    for (const child of children.children) {
      if (child.classList.contains('ldp-post')) renderedCount++;
    }
    const totalCount = Math.max(+(post.dataset.childReplyTotal || 0), renderedCount);
    const railToggle = children.querySelector(':scope > .ldp-nested-rail-toggle');
    const branchToggle = children.querySelector(':scope > .ldp-nested-branch-toggle');
    if (railToggle) {
      const railLabel = `点击收起 ${totalCount} 条回复`;
      railToggle.setAttribute('aria-label', railLabel);
      if (branchToggle) branchToggle.dataset.ldpTooltipLabel = railLabel;
    }
    if (renderedCount && post.classList.contains('ldp-reply') && !post._ldpPostData?.hidden) {
      setNestedReplyCollapsed(post, false);
    }
    if (!totalCount) {
      btn.classList.remove('show');
      post.classList.remove('ldp-has-child-branches');
      post.classList.remove('ldp-nested-branches-ready');
      clearCombinedParentPreviewLine(post);
      delete btn.dataset.replyControlKey;
      return;
    }
    const showBranches = !!renderedCount && !collapsed;
    post.classList.toggle('ldp-has-child-branches', showBranches);
    if (!showBranches) {
      post.classList.remove('ldp-nested-branches-ready');
      clearCombinedParentPreviewLine(post);
    }
    btn.classList.add('show');
    const controlKey = `${collapsed ? 'collapsed' : 'open'}:${totalCount}`;
    if (btn.dataset.replyControlKey !== controlKey) {
      btn.dataset.replyControlKey = controlKey;
      btn.setAttribute('aria-expanded', collapsed ? 'false' : 'true');
      btn.innerHTML = `${icon(collapsed ? 'chevronRight' : 'chevronDown')}<span>${collapsed ? `展开 ${totalCount} 条回复` : `收起 ${totalCount} 条回复`}</span>`;
    }
    if (!collapsed) syncNestedReplyBranches(children);
  }

  function setChildRepliesCollapsed(post, collapsed) {
    if (!post) return;
    post.classList.toggle('ldp-children-collapsed', !!collapsed);
    syncChildControls(post);
  }

  /* ============ 7. 渲染单条 ============ */
  function childReplyShellHtml(total) {
    return `<button class="ldp-btn ldp-collapse-replies" type="button" aria-expanded="true"></button>
      <div class="ldp-children">
        <button class="ldp-nested-rail-toggle" type="button" aria-label="点击收起 ${total} 条回复"></button>
        <svg class="ldp-nested-branch-toggle" aria-hidden="true" focusable="false" data-ldp-tooltip-label="点击收起 ${total} 条回复"><path class="ldp-nested-branch-hit-path"></path></svg>
        <div class="ldp-sub-actions">
          <button class="ldp-btn ldp-sub-page-btn ldp-sub-page-prev" type="button">${icon('chevronRight')}<span>上一页</span></button>
          <span class="ldp-sub-page-info"></span>
          <button class="ldp-btn ldp-sub-page-btn ldp-sub-page-next" type="button">${icon('chevronRight')}<span>下一页</span></button>
        </div>
      </div>
      <div class="ldp-sub-loading">加载楼中楼中…</div>`;
  }

  function readerPostIsRead(post, ctx) {
    if (!post) return false;
    if (post.read === true) return true;
    const postNumber = +(post.post_number || 0);
    const lastReadPostNumber = +(ctx && ctx.topicData && ctx.topicData.last_read_post_number || 0);
    return postNumber > 0 && lastReadPostNumber >= postNumber;
  }

  function postReadStateIconHtml(isRead) {
    return isRead
      ? icon('check', 'ldp-post-read-state-icon')
      : '<svg class="ldp-icon ldp-post-read-state-icon" viewBox="0 0 24 24" aria-hidden="true"><circle cx="12" cy="12" r="5.5"/></svg>';
  }

  function postReadStateHtml(isRead) {
    const state = isRead ? 'read' : 'unread';
    const label = isRead ? '该楼层已读' : '该楼层未读';
    return `<span class="ldp-post-read-state is-${state}" data-read-state="${state}" data-ldp-tooltip-label="${label}" role="img" aria-label="${label}">${postReadStateIconHtml(isRead)}</span>`;
  }

  function readerPostNodeInViewport(postNode, scrollRoot) {
    if (!postNode || !postNode.isConnected || !postNode.getClientRects().length) return false;
    const rect = postNode.getBoundingClientRect();
    const viewport = scrollRoot && scrollRoot.getBoundingClientRect
      ? scrollRoot.getBoundingClientRect()
      : { top: 0, right: window.innerWidth, bottom: window.innerHeight, left: 0 };
    return rect.bottom > viewport.top && rect.top < viewport.bottom &&
      rect.right > viewport.left && rect.left < viewport.right;
  }

  function syncPostReadState(postNode, isRead, options = {}) {
    if (!postNode) return;
    const marker = postNode.querySelector(':scope > .ldp-post-head > .ldp-post-read-state');
    if (!marker) return;
    const state = isRead ? 'read' : 'unread';
    if (postNode._ldpPostData) postNode._ldpPostData.read = !!isRead;
    if (marker.dataset.readState === state || marker.dataset.readTransitionState === state) return;
    const label = isRead ? '该楼层已读' : '该楼层未读';
    const cancelTransition = () => {
      if (marker._ldpReadStateSwapTimer) clearTimeout(marker._ldpReadStateSwapTimer);
      marker._ldpReadStateSwapTimer = 0;
      if (marker._ldpReadStateTimer) clearTimeout(marker._ldpReadStateTimer);
      marker._ldpReadStateTimer = 0;
      if (marker._ldpReadStateFinish) {
        marker.removeEventListener('animationend', marker._ldpReadStateFinish);
      }
      marker._ldpReadStateFinish = null;
      marker.classList.remove('is-confirming');
      delete marker.dataset.readTransitionState;
    };
    const applyVisual = () => {
      marker.dataset.readState = state;
      marker.classList.toggle('is-read', !!isRead);
      marker.classList.toggle('is-unread', !isRead);
      marker.setAttribute('aria-label', label);
      marker.dataset.ldpTooltipLabel = label;
      marker.removeAttribute('title');
      marker.innerHTML = postReadStateIconHtml(isRead);
      marker.dispatchEvent(new CustomEvent('ldp-tooltip-refresh', { bubbles: true, composed: true }));
    };
    const applyState = () => {
      cancelTransition();
      if (marker.dataset.readState !== state) applyVisual();
    };
    const reduceMotion = window.matchMedia &&
      window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    if (options.animate === true && isRead && !reduceMotion) {
      marker.dataset.readTransitionState = state;
      marker.classList.add('is-confirming');
      const finish = () => {
        if (marker._ldpReadStateFinish !== finish) return;
        applyState();
      };
      marker._ldpReadStateFinish = finish;
      marker.addEventListener('animationend', finish, { once: true });
      marker._ldpReadStateSwapTimer = setTimeout(() => {
        if (marker._ldpReadStateFinish !== finish) return;
        marker._ldpReadStateSwapTimer = 0;
        applyVisual();
      }, 625);
      marker._ldpReadStateTimer = setTimeout(finish, 1450);
      return;
    }
    applyState();
  }

  function syncConfirmedPostReadStateWhenVisible(node, ctx) {
    if (!node) return;
    const syncConfirmedState = () => syncPostReadState(node, true, { animate: true });
    if (readerPostNodeInViewport(node, ctx && ctx.scrollRoot)) {
      syncConfirmedState();
    } else if (ctx && ctx.tracker && typeof ctx.tracker.runWhenVisible === 'function') {
      ctx.tracker.runWhenVisible(node, syncConfirmedState);
    } else {
      syncPostReadState(node, true);
    }
  }

  function markReaderPostsRead(postNumbers, ctx) {
    const confirmed = new Set((postNumbers || []).map(Number).filter(Boolean));
    if (!confirmed.size || !ctx) return;
    if (!ctx.confirmedReadPostNumbers) ctx.confirmedReadPostNumbers = new Set();
    confirmed.forEach((postNumber) => ctx.confirmedReadPostNumbers.add(postNumber));
    const persistedPosts = new Map();
    const syncPostData = (post) => {
      if (!post || !confirmed.has(+(post.post_number || 0))) return;
      post.read = true;
      if (post.id) persistedPosts.set(+post.id, post);
    };
    const syncNode = (node) => {
      const postNumber = +(node && node.dataset && node.dataset.postNumber || 0);
      if (!confirmed.has(postNumber)) return;
      const postData = node._ldpPostData;
      syncPostData(postData);
      syncConfirmedPostReadStateWhenVisible(node, ctx);
    };
    if (ctx.modal) ctx.modal.querySelectorAll('.ldp-post').forEach(syncNode);
    if (ctx.streamNodeMap) {
      ctx.streamNodeMap.forEach((node) => {
        syncNode(node);
        if (node && node.querySelectorAll) node.querySelectorAll('.ldp-post').forEach(syncNode);
      });
    }
    if (ctx.subReplyState) {
      ctx.subReplyState.forEach((state) => {
        if (state && state.nodeCache) state.nodeCache.forEach(syncNode);
        if (state && Array.isArray(state.all)) state.all.forEach(syncPostData);
      });
    }
    if (ctx.directRepliesByParent) {
      ctx.directRepliesByParent.forEach((replies) => {
        if (replies) replies.forEach(syncPostData);
      });
    }
    postsFromPayload(ctx.topicData).forEach(syncPostData);
    if (!persistedPosts.size) return;
    if (ctx.loader && typeof ctx.loader.persistFetchedPosts === 'function') {
      ctx.loader.persistFetchedPosts(Array.from(persistedPosts.values()));
    } else if (ctx.topicData) {
      setCachedTopicData(ctx.topicId, ctx.topicData);
    }
  }

  function renderPost(p, isReply, ctx, options = {}) {
    const avatar = avatarWithFlairHtml(
      persistentAvatarHtml(
        p.avatar_template,
        48,
        'ldp-avatar',
        p.name || p.username || '?'
      ),
      p
    );
    const { count, acted, canAct } = likeInfo(p);
    const isOP = ctx.op && p.username === ctx.op;
    const isME = ME_USERNAME && p.username === ME_USERNAME;
    const time = fmtTime(p.created_at);
    const exactTime = fmtExactTime(p.created_at);
    const profileUrl = userProfileUrl(p.username);
    const userCardAttr = `data-user-card="${escAttr(p.username)}"`;
    const isTopicStarter = !isReply && !options.nestedPreview && +p.post_number === 1;
    const hiddenCollapsible = !!p.hidden && !options.nestedPreview;
    const deferContent = options.deferContent === true;
    const boostListHtml = deferContent
      ? (postHasBoostData(p.boosts)
        ? '<div class="ldp-boost-list ldp-boost-pending" aria-hidden="true"></div>'
        : '<div class="ldp-boost-list" hidden></div>')
      : renderBoostList(p.boosts, { canQuickBoost: canShowBoostButton(p), ctx });
    const contentHtml = deferContent
      ? `<div class="ldp-content cooked ldp-content-pending" aria-busy="true" style="--ldp-content-placeholder-height:${postContentPlaceholderHeight(p)}px"></div>`
      : '<div class="ldp-content cooked"></div>';
    const replyToPostNumber = +(p.reply_to_post_number || 0);
    const parentFloorHtml = options.showParentJump && isReply && replyToPostNumber
        ? `<button class="ldp-floor ldp-jump-parent" type="button" data-target-post-number="${replyToPostNumber}" aria-label="跳到父楼层 #${replyToPostNumber}">@#${replyToPostNumber}</button>`
        : '';
    const currentFloorHtml = options.nestedPreview
        ? `<button class="ldp-floor ldp-jump-self" type="button" data-target-post-number="${p.post_number}" data-parent-post-number="${replyToPostNumber || ''}" aria-label="跳到楼层 #${p.post_number}">#${p.post_number}</button>`
        : `<span class="ldp-floor ldp-body-floor${parentFloorHtml ? ' ldp-current-floor' : ''}">#${p.post_number}</span>`;
    const deferConfirmedReadAnimation = !!(ctx && ctx.confirmedReadPostNumbers &&
      ctx.confirmedReadPostNumbers.has(+(p.post_number || 0)));
    const readStateHtml = postReadStateHtml(
      deferConfirmedReadAnimation ? false : readerPostIsRead(p, ctx)
    );
    const collapseNested = options.forceExpanded
        ? false
        : hiddenCollapsible || options.forceCollapsed
          ? true
          : shouldCollapseNestedReply(p, isReply, options);
    const allowChildReplies = !ctx.isPostVoting && !options.nestedPreview && p.reply_count > 0;
    const childRepliesHtml = allowChildReplies ? childReplyShellHtml(p.reply_count) : '';

    const node = document.createElement('div');
    node.className = 'ldp-post' + (isReply ? ' ldp-reply ldp-reply-collapsible' : '') +
        (hiddenCollapsible ? ' ldp-hidden-collapsible' : '') +
        (options.nestedPreview ? ' ldp-nested-preview' : '') +
        (collapseNested ? ' ldp-nested-collapsed' : '') +
        (allowChildReplies && (isTopicStarter || PREFS.expandNestedRepliesByDefault !== true)
          ? ' ldp-children-collapsed'
          : '');
    node.dataset.postId = p.id;
    node.dataset.postNumber = p.post_number;
    node.dataset.username = p.username || '';
    node.dataset.createdAt = p.created_at || '';
    node.dataset.ldpContentHydrated = deferContent ? '0' : '1';
    node._ldpPostData = p;
    node._ldpReaderContext = ctx;
    if (replyToPostNumber) node.dataset.replyToPostNumber = replyToPostNumber;
    if (allowChildReplies) node.dataset.childReplyTotal = String(p.reply_count);
    node.innerHTML = `
      ${isReply || hiddenCollapsible ? '<button class="ldp-btn ldp-nested-toggle" type="button"></button>' : ''}
      <div class="ldp-post-head">
        ${avatar ? `<button class="ldp-user-link ldp-avatar-link" type="button" data-user-avatar-preview data-tooltip ${userCardAttr} aria-label="查看 ${escAttr(p.name || p.username)} 的头像原图">${avatar}</button>` : ''}
        <a class="ldp-user-link ldp-author" href="${profileUrl}" target="_blank" rel="noopener" ${userCardAttr}>${esc(p.name || p.username)}</a>
        ${isME ? '<span class="ldp-me">ME</span>' : ''}
        <a class="ldp-user-link ldp-user" href="${profileUrl}" target="_blank" rel="noopener" ${userCardAttr}>@${esc(p.username)}</a>
        ${isOP ? '<span class="ldp-op">OP</span>' : ''}
        ${time ? `<span class="ldp-time"${exactTime ? ` data-exact-time="${escAttr(exactTime)}"` : ''}><span class="ldp-time-relative">· ${esc(time)}</span></span>` : ''}
        ${p.hidden ? '<span class="ldp-special-badge ldp-hidden-badge warn">已隐藏</span>' : ''}
        ${parentFloorHtml}${currentFloorHtml}${readStateHtml}
      </div>
      ${contentHtml}
      <div class="ldp-reactions">
        <div class="ldp-actions">
          <button class="ldp-btn ldp-like ${acted ? 'liked' : ''}"
            data-acted="${acted ? '1' : '0'}" aria-label="${acted ? '取消点赞' : '点赞'}" ${canAct || acted ? '' : 'disabled'}>
            ${icon('heart')} <span class="ldp-like-count">${count}</span>
          </button>
          ${compactPostActionsHtml(p, ctx)}
        </div>
      </div>
      ${boostListHtml}
      ${childRepliesHtml}
      ${isTopicStarter ? topicFooterActionsHtml(p, ctx) : ''}
    `;
    if (deferConfirmedReadAnimation) syncConfirmedPostReadStateWhenVisible(node, ctx);
    if (!deferContent) {
      const content = node.querySelector(':scope > .ldp-content');
      if (content) setPostCookedContent(content, p.cooked, p.link_counts);
      renderPostPolls(node, ctx);
      renderPostSpecialContent(node, ctx);
    }
    prepareReaderMedia(node);
    hydratePersistentAvatarImages(node);
    syncReaderSvgSymbols(node);
    if (isTopicStarter) syncTopicActionControls(ctx);
    syncPostActionControls(node, ctx);
    if (isReply || hiddenCollapsible) setNestedReplyCollapsed(node, collapseNested);
    return node;
  }

  /* ============ 8. 回复框 ============ */
  function lookupDiscourse(name) {
    const candidates = Array.from(new Set([HOST_PAGE_WINDOW, window].filter(Boolean)));
    for (const candidate of candidates) {
      try {
        if (!candidate.Discourse || !candidate.Discourse.__container__ ||
          typeof candidate.Discourse.__container__.lookup !== 'function') continue;
        const item = candidate.Discourse.__container__.lookup(name);
        if (item) return item;
      } catch (e) {}
    }
    return null;
  }

  function tryRequire(name) {
    const candidates = Array.from(new Set([HOST_PAGE_WINDOW, window].filter(Boolean)));
    for (const candidate of candidates) {
      try {
        const req = candidate.require || candidate.requirejs;
        if (typeof req !== 'function') continue;
        const module = req.call(candidate, name);
        if (module) return module;
      } catch (e) {}
    }
    return null;
  }

  function navigateDiscourseHostRoute(href) {
    let route;
    try {
      const url = new URL(String(href || ''), location.href);
      if (url.origin !== location.origin) return false;
      route = `${url.pathname}${url.search}${url.hash}`;
    } catch (e) {
      return false;
    }
    const discourseUrlModule = tryRequire('discourse/lib/url');
    const routeOwners = Array.from(new Set([
      discourseUrlModule,
      discourseUrlModule && discourseUrlModule.default,
      HOST_PAGE_WINDOW.DiscourseURL,
      HOST_PAGE_WINDOW.Discourse && HOST_PAGE_WINDOW.Discourse.URL,
    ].filter(Boolean)));
    for (const owner of routeOwners) {
      if (typeof owner.routeTo !== 'function') continue;
      try {
        const transition = owner.routeTo(route);
        if (transition && typeof transition.catch === 'function') {
          transition.catch(() => {});
        }
        return true;
      } catch (e) {}
    }
    return false;
  }

  function openEmbeddedReaderLinkInHost(event, link, readerWorkspace) {
    if (!link || !readerWorkspace || !readerWorkspace.isEmbedded() || link.hasAttribute('download') || link.matches('a.lightbox') ||
      event.button && event.button !== 0 || event.altKey || event.ctrlKey || event.metaKey || event.shiftKey) return false;
    let url;
    try {
      url = new URL(link.getAttribute('href') || link.href || '', location.href);
    } catch (error) {
      return false;
    }
    if (!/^https?:$/i.test(url.protocol) || url.origin !== location.origin) return false;
    url.searchParams.delete(NATIVE_BYPASS_PARAM);
    const topicRoute = extractTopicRouteFromUrl(url.href);
    if (topicRoute) return false;
    const previousSuppressedTopicId = AUTO_OPEN_SUPPRESSED_TOPIC_ID;
    event.preventDefault();
    event.stopPropagation();
    if (navigateDiscourseHostRoute(url.href)) return true;
    AUTO_OPEN_SUPPRESSED_TOPIC_ID = previousSuppressedTopicId;
    showSelectionToast('LINUX DO 站内导航暂不可用，请稍后重试');
    return true;
  }

  function refreshDiscourseHostRoute() {
    const router = lookupDiscourse('service:router');
    if (!router || typeof router.refresh !== 'function') return false;
    try {
      const transition = router.refresh();
      if (transition && typeof transition.catch === 'function') {
        transition.catch(() => {});
      }
      return true;
    } catch (e) {
      return false;
    }
  }

  function getUserCardUsername(link) {
    const username = link && (link.dataset.userCard || link.getAttribute('data-user-card'));
    return cleanUsernameValue(username);
  }

  function openDiscourseActionRoute(href) {
    if (navigateDiscourseHostRoute(href)) return true;
    try {
      location.assign(new URL(href, BASE).href);
      return true;
    } catch (error) {
      return false;
    }
  }

  async function openDirectPrivateMessage(username, ctx) {
    const href = `/new-message?username=${encodeURIComponent(username)}`;
    if (!navigateDiscourseHostRoute(href)) return openDiscourseActionRoute(href);
    if (!await waitForNativeComposerPopup(ctx)) return false;
    return !!(ctx && ctx.nativeComposerWindow
      && ctx.nativeComposerWindow.open(document.querySelector('#reply-control')));
  }

  async function openReaderEndorsementDialog(ctx, user) {
    const username = String(user && user.username || '').trim();
    if (!ctx || !username) return false;
    const data = await fetchJSON(`${BASE}/category-experts/endorsable-categories/${encodeURIComponent(username)}.json`, {
      key: `user-endorsements:${username}`,
      priority: POST_REQUEST_PRIORITY.userCard,
    });
    const categories = Array.isArray(data && data.categories) ? data.categories : [];
    const remaining = Number(data && data.extras && data.extras.remaining_endorsements);
    const existingIds = new Set((Array.isArray(user.category_expert_endorsements)
      ? user.category_expert_endorsements
      : []).map((item) => Number(item && item.category_id)).filter(Number.isFinite));
    if (!categories.length) throw new Error('当前没有可认可的类别');
    const optionsHtml = categories.map((category) => {
      const categoryId = Number(category && category.id);
      const existing = existingIds.has(categoryId);
      return `<label class="ldp-reader-action-option">
        <input type="checkbox" name="category_id" value="${categoryId}"${existing ? ' checked disabled' : ''}>
        <span class="ldp-reader-action-option-copy"><strong>${esc(category && category.name || `类别 ${categoryId}`)}</strong>
          <small>${existing ? '已经认可' : '选择后将认可该用户为此类别的专家'}</small></span>
      </label>`;
    }).join('');
    return !!openReaderActionDialog(ctx, {
      title: `认可 @${username}`,
      intro: Number.isFinite(remaining) ? `今天还可新增 ${remaining} 次认可。` : '选择要认可的专家类别。',
      submitLabel: '确认认可',
      initialFocus: 'input[name="category_id"]:not(:disabled)',
      bodyHtml: `<div class="ldp-reader-action-options">${optionsHtml}</div>`,
      onSubmit: async (formData) => {
        if (Number.isFinite(remaining) && remaining < 1) throw new Error('今天的认可次数已用完');
        const addedIds = formData.getAll('category_id').map(Number)
          .filter((categoryId) => Number.isFinite(categoryId) && !existingIds.has(categoryId));
        if (!addedIds.length) throw new Error('请选择一个尚未认可的类别');
        const categoryIds = Array.from(new Set([...existingIds, ...addedIds]));
        const response = await apiSend(
          `${BASE}/category-experts/endorse/${encodeURIComponent(username)}.json`,
          'PUT',
          { categoryIds }
        );
        user.category_expert_endorsements = Array.isArray(response && response.category_expert_endorsements)
          ? response.category_expert_endorsements
          : user.category_expert_endorsements;
        setCachedUserCard(username, user, 0);
        return '认可已提交';
      },
    });
  }

  function userNotificationLevel(user) {
    if (user && user.ignored) return 'ignore';
    if (user && user.muted) return 'mute';
    return 'normal';
  }

  const USER_NOTIFICATION_LEVEL_LABELS = {
    normal: '常规',
    mute: '免打扰',
    ignore: '忽略',
  };

  async function saveReaderUserNotificationLevel(username, user, level, extraParams = {}) {
    if (!username || !Object.hasOwn(USER_NOTIFICATION_LEVEL_LABELS, level)) {
      throw new Error('无效的消息设置');
    }
    await apiSend(`${BASE}/u/${encodeURIComponent(username)}/notification_level.json`, 'PUT', {
      notification_level: level,
      ...extraParams,
    });
    if (user) {
      user.muted = level === 'mute';
      user.ignored = level === 'ignore';
      setCachedUserCard(username, user, 0);
    }
    return USER_NOTIFICATION_LEVEL_LABELS[level];
  }

  function openReaderIgnoreDurationDialog(ctx, username, user) {
    const durations = [
      { days: 1, label: '1 天' },
      { days: 7, label: '1 周' },
      { days: 30, label: '1 个月' },
      { days: 120, label: '4 个月' },
      { days: 365, label: '1 年' },
    ];
    return openReaderActionDialog(ctx, {
      title: `忽略 @${username}`,
      intro: 'Discourse 要求为“忽略”设置截止时间；到期后会自动恢复为常规。',
      submitLabel: '确认忽略',
      initialFocus: 'select[name="ignore_days"]',
      bodyHtml: `<label class="ldp-reader-action-field"><span>忽略期限</span>
        <select class="ldp-reader-select" name="ignore_days">${durations.map((item) => `<option value="${item.days}"${item.days === 30 ? ' selected' : ''}>${item.label}</option>`).join('')}</select>
      </label>`,
      onSubmit: async (formData) => {
        const days = Number(formData.get('ignore_days'));
        if (!durations.some((item) => item.days === days)) throw new Error('请选择有效的忽略期限');
        const expiringAt = new Date(Date.now() + days * 86400000).toISOString();
        await saveReaderUserNotificationLevel(username, user, 'ignore', { expiring_at: expiringAt });
        return `已忽略 @${username}`;
      },
    });
  }

  async function runDirectUserCardAction(action, username, user, ctx) {
    if (!username || !['message', 'endorse', 'follow'].includes(action)) {
      return { ok: false, reason: 'invalid-action' };
    }
    try {
      if (action === 'message') {
        const opened = await openDirectPrivateMessage(username, ctx);
        return { ok: opened, reason: opened ? '' : 'route-unavailable' };
      }
      if (action === 'endorse') {
        const opened = await openReaderEndorsementDialog(ctx, user || { username });
        return { ok: opened, reason: opened ? '' : 'endorsement-unavailable' };
      }
      if (action === 'follow') {
        if (user && user.can_follow === false && !user.is_followed) {
          return { ok: false, reason: 'follow-not-allowed' };
        }
        const followed = !!(user && user.is_followed);
        await apiSend(`${BASE}/follow/${encodeURIComponent(username)}.json`, followed ? 'DELETE' : 'PUT');
        if (user) {
          const totalFollowers = Number(user.total_followers);
          user.is_followed = !followed;
          if (Number.isFinite(totalFollowers)) user.total_followers = Math.max(0, totalFollowers + (followed ? -1 : 1));
          setCachedUserCard(username, user, 0);
        }
        invalidateUserFollowList(username, 'followers');
        invalidateUserFollowList(ME_USERNAME, 'following');
        return { ok: true, reason: '', keepOpen: true, followed: !followed };
      }
    } catch (error) {
      console.warn('[LINUX DO reader] direct user card action failed', { action, error });
      return { ok: false, reason: 'action-failed', error };
    }
  }

  function emitUserCardUpdate(entry, user, phase) {
    if (!entry || !entry.listeners) return;
    entry.listeners.forEach((listener) => {
      try { listener(user, phase); } catch (e) {}
    });
  }

  function userTrustLevel(user) {
    const rawLevel = user && user.trust_level;
    const direct = Number(rawLevel);
    if (rawLevel != null && rawLevel !== '' && Number.isFinite(direct)) return direct;
    const labels = [
      user && user.title,
      user && user.flair_name,
      user && user.primary_group_name,
      ...(Array.isArray(user && user.groups)
        ? user.groups.flatMap((group) => [group && group.name, group && group.full_name, group && group.title])
        : []),
    ];
    for (const label of labels) {
      const match = String(label || '').match(/(?:^|[,，\s])lv\s*([0-9]+)(?:\b|$)/i);
      if (match) return Number(match[1]);
    }
    return null;
  }

  function userDetailsChecked(user, detail) {
    const checkedAt = Number(user && user[`_ldp_${detail}_checked_at`] || 0);
    return checkedAt > 0 && Date.now() - checkedAt < USER_CARD_CACHE_FRESH_FOR;
  }

  function fetchUserJSON(path, key, options = null) {
    const requestOptions = { key, priority: POST_REQUEST_PRIORITY.userCard };
    if (options) Object.assign(requestOptions, {
      cacheMode: options.cacheMode,
      allowStaleOnError: options.allowStaleOnError,
    });
    return fetchJSON(`${BASE}${path}`, requestOptions);
  }

  async function fetchUserProfileDetails(username, options = {}) {
    try {
      const data = await fetchUserJSON(`/u/${encodeURIComponent(username)}.json`, `user-profile:${username}`, options);
      return data && (data.user || data);
    } catch (error) {
      if (shouldStopReaderFallback(error)) throw error;
      const data = await fetchUserJSON(`/u/${encodeURIComponent(username)}/card.json`, `user-card:${username}`, options);
      return data && (data.user || data);
    }
  }

  function uniqueUserBadges(source) {
    const unique = new Map();
    (Array.isArray(source) ? source : []).forEach((badge) => {
      if (!badge) return;
      const badgeId = Number(badge.id || badge.badge_id) || 0;
      const name = String(badge.name || '').trim();
      const key = badgeId ? `id:${badgeId}` : `name:${name.toLocaleLowerCase()}`;
      if (!badgeId && !name) return;
      const previous = unique.get(key);
      const grantedAt = Date.parse(badge.granted_at || '') || 0;
      const previousGrantedAt = Date.parse(previous && previous.granted_at || '') || 0;
      if (!previous || grantedAt >= previousGrantedAt) unique.set(key, badge);
    });
    return Array.from(unique.values());
  }

  async function fetchUserBadges(username) {
    const data = await fetchUserJSON(`/user-badges/${encodeURIComponent(username)}.json`, `user-badges:${username}`);
    const badgesById = new Map((Array.isArray(data && data.badges) ? data.badges : [])
      .map((badge) => [Number(badge && badge.id), badge]));
    return uniqueUserBadges((Array.isArray(data && data.user_badges) ? data.user_badges : []).map((grant) => {
      const badge = badgesById.get(Number(grant && grant.badge_id)) || {};
      return Object.assign({}, badge, grant, {
        id: Number(grant && grant.badge_id || badge.id) || 0,
        name: String(badge.name || grant && grant.name || '').trim(),
      });
    }).filter((badge) => badge.id && badge.name && badge.enabled !== false));
  }

  function normalizeUserFollowList(data, type) {
    const source = Array.isArray(data)
      ? data
      : Array.isArray(data && data.users)
        ? data.users
        : Array.isArray(data && data[type])
          ? data[type]
          : [];
    return source.map((entry) => {
      const user = entry && (entry.user || entry);
      const username = cleanUsernameValue(user && user.username);
      if (!username) return null;
      const name = String(user.name || username).trim();
      return {
        username,
        name,
        avatar_template: String(user.avatar_template || ''),
        flair_name: user.flair_name,
        flair_url: user.flair_url,
        flair_bg_color: user.flair_bg_color,
        flair_color: user.flair_color,
        searchText: pinyinSearchForms(`${username} ${name}`).join(' '),
      };
    }).filter(Boolean);
  }

  function cachedUserFollowList(key) {
    const cached = USER_FOLLOW_LIST_CACHE.get(key);
    if (!cached || Date.now() - cached.at > USER_FOLLOW_LIST_CACHE_FRESH_FOR) {
      USER_FOLLOW_LIST_CACHE.delete(key);
      return null;
    }
    USER_FOLLOW_LIST_CACHE.delete(key);
    USER_FOLLOW_LIST_CACHE.set(key, cached);
    return cached.users;
  }

  function invalidateUserFollowList(username, type) {
    username = cleanUsernameValue(username);
    if (!username || !['following', 'followers'].includes(type)) return;
    USER_FOLLOW_LIST_CACHE.delete(authScopedCacheKey(`${username}:${type}`));
    const policy = responseCachePolicy(`${BASE}/u/${encodeURIComponent(username)}/follow/${type}`);
    if (policy) void deleteStoredResponseCacheEntry(policy.id);
  }

  async function fetchUserFollowList(username, type) {
    username = cleanUsernameValue(username);
    if (!username || !['following', 'followers'].includes(type)) return [];
    const cacheKey = authScopedCacheKey(`${username}:${type}`);
    const cached = cachedUserFollowList(cacheKey);
    if (cached) return cached;
    if (USER_FOLLOW_LIST_REQUESTS.has(cacheKey)) return USER_FOLLOW_LIST_REQUESTS.get(cacheKey);
    const request = fetchUserJSON(
      `/u/${encodeURIComponent(username)}/follow/${type}`,
      `user-${type}:${username}`
    ).then((data) => {
      const users = normalizeUserFollowList(data, type);
      USER_FOLLOW_LIST_CACHE.delete(cacheKey);
      USER_FOLLOW_LIST_CACHE.set(cacheKey, { users, at: Date.now() });
      while (USER_FOLLOW_LIST_CACHE.size > USER_FOLLOW_LIST_CACHE_MAX_ENTRIES) {
        USER_FOLLOW_LIST_CACHE.delete(USER_FOLLOW_LIST_CACHE.keys().next().value);
      }
      return users;
    }).finally(() => USER_FOLLOW_LIST_REQUESTS.delete(cacheKey));
    USER_FOLLOW_LIST_REQUESTS.set(cacheKey, request);
    return request;
  }

  async function fetchUserCard(username, onUpdate) {
    username = cleanUsernameValue(username);
    if (!username) return null;
    const existing = USER_CARD_REQUESTS.get(username);
    if (existing && !existing.cancelled) {
      if (typeof onUpdate === 'function') {
        existing.listeners.add(onUpdate);
        if (existing.basic) onUpdate(existing.basic, 'stats');
      }
      return existing.promise;
    }
    if (existing) USER_CARD_REQUESTS.delete(username);
    const cached = getCachedUserCard(username);
    const profileChecked = cached && userDetailsChecked(cached, 'profile');
    const summaryChecked = cached && userDetailsChecked(cached, 'summary');
    const badgesChecked = cached && userDetailsChecked(cached, 'badges');
    if (cached && profileChecked && summaryChecked && badgesChecked) {
      if (typeof onUpdate === 'function') onUpdate(cached, 'ready');
      return cached;
    }
    if (cached && typeof onUpdate === 'function') onUpdate(cached, 'stats');
    const profilePromise = profileChecked
      ? Promise.resolve(cached)
      : fetchUserProfileDetails(username);
    const summaryPromise = summaryChecked
      ? Promise.resolve(cached.user_summary)
      : fetchUserSummary(username);
    const badgesPromise = badgesChecked
      ? Promise.resolve(Array.isArray(cached.user_badges) ? cached.user_badges : [])
      : fetchUserBadges(username);
    const supplementalPromise = Promise.allSettled([summaryPromise, badgesPromise]);
    const entry = { listeners: new Set(), basic: null, promise: null, cancelled: false };
    if (typeof onUpdate === 'function') entry.listeners.add(onUpdate);
    const request = (async () => {
      const profile = await profilePromise;
      const user = Object.assign({}, cached || {}, profile || {}, {
        _ldp_profile_checked_at: profileChecked
          ? cached._ldp_profile_checked_at
          : Date.now(),
      });
      entry.basic = user;
      setCachedUserCard(username, user);
      emitUserCardUpdate(entry, user, 'stats');
      if (entry.cancelled) return user;
      const [summaryResult, badgesResult] = await supplementalPromise;
      if (badgesResult.status === 'fulfilled') {
        user.user_badges = badgesResult.value;
      }
      if (summaryResult.status === 'rejected') throw summaryResult.reason;
      user.user_summary = summaryResult.value;
      user._ldp_summary_checked_at = Date.now();
      setCachedUserCard(username, user, 0);
      emitUserCardUpdate(entry, user, 'ready');
      return user;
    })().finally(() => {
      if (USER_CARD_REQUESTS.get(username) === entry) USER_CARD_REQUESTS.delete(username);
    });
    entry.promise = request;
    USER_CARD_REQUESTS.set(username, entry);
    return request;
  }

  function cancelQueuedUserCardRequests(username, scheduler = ACTIVE_READER_REQUEST_SCHEDULER) {
    username = cleanUsernameValue(username);
    if (!username) return;
    const entry = USER_CARD_REQUESTS.get(username);
    if (entry) entry.cancelled = true;
    if (!scheduler) return;
    [
      `user-profile:${username}`,
      `user-card:${username}`,
      `user-summary:${username}`,
      `user-directory:${username}`,
      `user-badges:${username}`,
      `user-following:${username}`,
      `user-followers:${username}`,
    ].forEach((key) => scheduler.cancelQueued(key));
  }

  async function fetchUserSummary(username, options = {}) {
    username = cleanUsernameValue(username);
    if (!username) return null;
    let summary = null;
    try {
      const data = await fetchUserJSON(`/u/${encodeURIComponent(username)}/summary.json`, `user-summary:${username}`, options);
      summary = data && (data.user_summary || data.summary || data);
    } catch (e) {
      if (shouldStopReaderFallback(e)) throw e;
      summary = null;
    }
    const hasStats = summary && ['post_count', 'posts_count', 'likes_received', 'likes_given', 'topic_count', 'topics_entered']
      .some((key) => summary[key] != null && summary[key] !== '');
    const directoryStats = hasStats ? null : await fetchUserDirectoryStats(username, options);
    return Object.assign({}, directoryStats || {}, summary || {});
  }

  async function fetchUserDirectoryStats(username, options = {}) {
    username = cleanUsernameValue(username);
    if (!username) return null;
    try {
      const qs = new URLSearchParams();
      qs.set('period', 'all');
      qs.set('order', 'likes_received');
      qs.set('username', username);
      const data = await fetchUserJSON(`/directory_items.json?${qs}`, `user-directory:${username}`, options);
      const item = data && Array.isArray(data.directory_items) && data.directory_items[0];
      if (!item) return null;
      return {
        post_count: item.post_count,
        likes_received: item.likes_received,
        likes_given: item.likes_given,
        topic_count: item.topic_count,
      };
    } catch (e) {
      if (shouldStopReaderFallback(e)) throw e;
      return null;
    }
  }

  async function fetchSettingsUserInfo(username, force = false) {
    username = cleanUsernameValue(username);
    if (!username) return null;
    const cached = getCachedUserCard(username);
    if (!force && cached && userDetailsChecked(cached, 'profile') && userDetailsChecked(cached, 'summary')) return cached;
    const requestOptions = force
      ? { cacheMode: 'refresh', allowStaleOnError: false }
      : { cacheMode: 'default' };
    const [profile, summary] = await Promise.all([
      fetchUserProfileDetails(username, requestOptions),
      fetchUserSummary(username, requestOptions),
    ]);
    const checkedAt = Date.now();
    const user = Object.assign({}, cached || {}, profile || {}, {
      username,
      user_summary: summary,
      _ldp_profile_checked_at: checkedAt,
      _ldp_summary_checked_at: checkedAt,
      _ldp_user_info_checked_at: checkedAt,
    });
    setCachedUserCard(username, user, 0);
    return user;
  }

  function getFallbackUserCard() {
    let card = readerPortalQuery('.ldp-user-card-fallback:not(.ldp-user-card-follow-preview)');
    if (!card) {
      card = document.createElement('div');
      card.className = 'ldp-user-card-fallback';
      appendReaderPortalNode(card);
    }
    return card;
  }

  function getUserCardFollowPreview() {
    let card = readerPortalQuery('.ldp-user-card-follow-preview');
    if (card) return card;
    card = document.createElement('div');
    card.className = 'ldp-user-card-fallback ldp-user-card-follow-preview';
    appendReaderPortalNode(card);
    return card;
  }

  function getUserCardFollowPanel() {
    let panel = readerPortalQuery('.ldp-user-card-follow-panel');
    if (panel) return panel;
    panel = document.createElement('section');
    panel.id = 'ldp-user-card-follow-panel';
    panel.className = 'ldp-user-card-follow-panel';
    panel.setAttribute('aria-label', '关注人员列表');
    panel.hidden = true;
    panel.innerHTML = `
      <header><strong class="ldp-user-card-follow-title"></strong>
        <button type="button" data-user-card-follow-close aria-label="关闭关注人员列表">×</button></header>
      <nav class="ldp-user-card-breadcrumbs" aria-label="用户卡层级" hidden></nav>
      <label class="ldp-user-card-follow-search"><span>检索</span>
        <input type="search" autocomplete="off" spellcheck="false" placeholder="昵称、用户名或拼音">
      </label>
      <div class="ldp-user-card-follow-summary" aria-live="polite"></div>
      <div class="ldp-user-card-follow-list" role="list"></div>
      <nav class="ldp-user-card-follow-pagination" aria-label="人员列表分页" hidden>
        <button type="button" data-user-card-follow-page="previous">上一页</button>
        <span aria-live="polite"></span>
        <button type="button" data-user-card-follow-page="next">下一页</button>
      </nav>`;
    appendReaderPortalNode(panel);
    return panel;
  }

  function hideFallbackUserCard() {
    const card = readerPortalQuery('.ldp-user-card-fallback:not(.ldp-user-card-follow-preview)');
    if (card) card.classList.remove('open');
  }

  function fallbackUserCardOpen() {
    return !!readerPortalQuery('.ldp-user-card-fallback.open:not(.ldp-user-card-follow-preview)');
  }

  function positionFallbackUserCardNotificationMenu(card) {
    const menu = card && card.querySelector('.ldp-user-card-notification-menu:not([hidden])');
    const actions = card && card.querySelector('.ldp-user-card-actions');
    if (!menu || !actions) return;
    const margin = 10;
    const gap = 6;
    const rect = actions.getBoundingClientRect();
    const width = Math.min(rect.width, window.innerWidth - margin * 2);
    menu.style.width = `${Math.round(width)}px`;
    const height = menu.offsetHeight;
    const spaceAbove = rect.top - margin - gap;
    const spaceBelow = window.innerHeight - rect.bottom - margin - gap;
    const opensAbove = spaceBelow < height && spaceAbove > spaceBelow;
    const preferredTop = opensAbove ? rect.top - height - gap : rect.bottom + gap;
    const left = Math.max(margin, Math.min(rect.left, window.innerWidth - width - margin));
    const top = Math.max(margin, Math.min(preferredTop, window.innerHeight - height - margin));
    menu.style.left = `${Math.round(left)}px`;
    menu.style.top = `${Math.round(top)}px`;
  }

  function positionFallbackUserCard(card, anchor) {
    card.style.removeProperty('max-height');
    const rect = anchor.getBoundingClientRect();
    const margin = 10;
    const width = card.offsetWidth || 300;
    const height = Math.min(card.offsetHeight || 220, window.innerHeight - margin * 2);
    const left = Math.max(margin, Math.min(rect.left, window.innerWidth - width - margin));
    let top = rect.bottom + 8;
    if (top + height > window.innerHeight - margin) top = Math.max(margin, rect.top - height - 8);
    card.style.left = `${Math.round(left)}px`;
    card.style.top = `${Math.round(top)}px`;
    positionFallbackUserCardNotificationMenu(card);
  }

  function positionUserCardFollowPanel(panel, card) {
    if (!panel || panel.hidden || !card) return;
    const margin = 10;
    const gap = 8;
    panel.style.removeProperty('max-height');
    card.style.removeProperty('max-height');
    const cardRect = card.getBoundingClientRect();
    const width = panel.offsetWidth || 320;
    const height = Math.min(panel.offsetHeight || 220, window.innerHeight - margin * 2);
    const right = cardRect.right + gap;
    const left = cardRect.left - width - gap;
    const preferredLeft = right + width <= window.innerWidth - margin ? right : left;
    const fallbackLeft = Math.max(margin, Math.min(preferredLeft, window.innerWidth - width - margin));
    const fallbackTop = Math.max(margin, Math.min(cardRect.top, window.innerHeight - height - margin));
    const avatarViewer = readerPortalQuery('.ldp-avatar-viewer');
    const viewerRect = avatarViewer && avatarViewer.isConnected && avatarViewer._ldpAnchorCard === card
      ? avatarViewer.getBoundingClientRect()
      : null;
    const overlaps = (first, second) => first.left < second.right + gap && first.right + gap > second.left &&
      first.top < second.bottom + gap && first.bottom + gap > second.top;
    const fallbackRect = {
      left: fallbackLeft,
      top: fallbackTop,
      right: fallbackLeft + width,
      bottom: fallbackTop + height,
    };
    if (!viewerRect || !overlaps(fallbackRect, viewerRect)) {
      panel.style.left = `${Math.round(fallbackLeft)}px`;
      panel.style.top = `${Math.round(fallbackTop)}px`;
      return;
    }

    const minimumPanelHeight = Math.min(height, 150);
    const freeRegions = [
      { left: margin, top: margin, right: viewerRect.left - gap, bottom: window.innerHeight - margin },
      { left: viewerRect.right + gap, top: margin, right: window.innerWidth - margin, bottom: window.innerHeight - margin },
      { left: margin, top: margin, right: window.innerWidth - margin, bottom: viewerRect.top - gap },
      { left: margin, top: viewerRect.bottom + gap, right: window.innerWidth - margin, bottom: window.innerHeight - margin },
    ].filter((region) => region.right - region.left >= width && region.bottom - region.top >= minimumPanelHeight);
    const placements = freeRegions.flatMap((region) => {
      const availableHeight = region.bottom - region.top;
      const placedHeight = Math.min(height, availableHeight);
      const candidateLefts = new Set([
        Math.max(region.left, Math.min(cardRect.left, region.right - width)),
        region.left,
        region.right - width,
      ]);
      const candidateTops = new Set([
        Math.max(region.top, Math.min(cardRect.top, region.bottom - placedHeight)),
        region.top,
        region.bottom - placedHeight,
      ]);
      return Array.from(candidateLefts).flatMap((placedLeft) => Array.from(candidateTops).map((placedTop) => {
        const rect = {
          left: placedLeft,
          top: placedTop,
          right: placedLeft + width,
          bottom: placedTop + placedHeight,
        };
        return {
          left: placedLeft,
          top: placedTop,
          height: placedHeight,
          rect,
          score: Math.abs(placedLeft - fallbackLeft) + Math.abs(placedTop - fallbackTop) + (height - placedHeight) * 3,
        };
      }));
    }).filter((placement) => !overlaps(placement.rect, cardRect))
      .sort((first, second) => first.score - second.score);
    if (placements.length) {
      const placement = placements[0];
      if (placement.height < height) panel.style.maxHeight = `${Math.floor(placement.height)}px`;
      panel.style.left = `${Math.round(placement.left)}px`;
      panel.style.top = `${Math.round(placement.top)}px`;
      return;
    }

    const cardWidth = cardRect.width;
    const cardHeight = Math.min(cardRect.height, window.innerHeight - margin * 2);
    const minimumCardHeight = Math.min(cardHeight, 180);
    const stackedRegions = freeRegions.filter((region) =>
      region.right - region.left >= Math.max(cardWidth, width) &&
      region.bottom - region.top >= minimumCardHeight + gap + minimumPanelHeight
    ).map((region) => {
      const availableHeight = region.bottom - region.top - gap;
      const desiredTotal = Math.max(1, cardHeight + height);
      const placedCardHeight = Math.max(minimumCardHeight, Math.min(
        availableHeight - minimumPanelHeight,
        Math.round(availableHeight * cardHeight / desiredTotal)
      ));
      const placedPanelHeight = Math.min(height, availableHeight - placedCardHeight);
      const groupHeight = placedCardHeight + gap + placedPanelHeight;
      const groupTop = Math.max(region.top, Math.min(cardRect.top, region.bottom - groupHeight));
      const placedCardLeft = Math.max(region.left, Math.min(cardRect.left, region.right - cardWidth));
      const placedPanelLeft = Math.max(region.left, Math.min(placedCardLeft, region.right - width));
      return {
        cardLeft: placedCardLeft,
        cardTop: groupTop,
        cardHeight: placedCardHeight,
        panelLeft: placedPanelLeft,
        panelTop: groupTop + placedCardHeight + gap,
        panelHeight: placedPanelHeight,
        score: Math.abs(placedCardLeft - cardRect.left) + Math.abs(groupTop - cardRect.top) +
          (cardHeight - placedCardHeight) * 2 + (height - placedPanelHeight) * 2,
      };
    }).sort((first, second) => first.score - second.score);
    if (stackedRegions.length) {
      const placement = stackedRegions[0];
      card.style.left = `${Math.round(placement.cardLeft)}px`;
      card.style.top = `${Math.round(placement.cardTop)}px`;
      if (placement.cardHeight < cardHeight) card.style.maxHeight = `${Math.floor(placement.cardHeight)}px`;
      panel.style.left = `${Math.round(placement.panelLeft)}px`;
      panel.style.top = `${Math.round(placement.panelTop)}px`;
      if (placement.panelHeight < height) panel.style.maxHeight = `${Math.floor(placement.panelHeight)}px`;
      positionFallbackUserCardNotificationMenu(card);
      return;
    }

    panel.style.left = `${Math.round(fallbackLeft)}px`;
    panel.style.top = `${Math.round(fallbackTop)}px`;
  }

  function positionUserCardFollowPreview(preview, panel, card) {
    if (!preview || !panel || panel.hidden || !card) return;
    const margin = 10;
    const gap = 8;
    const panelRect = panel.getBoundingClientRect();
    const cardRect = card.getBoundingClientRect();
    const width = preview.offsetWidth || 320;
    const height = Math.min(preview.offsetHeight || 220, window.innerHeight - margin * 2);
    const panelIsRightOfCard = panelRect.left >= cardRect.right;
    const preferredLeft = panelIsRightOfCard ? panelRect.right + gap : panelRect.left - width - gap;
    const alternateLeft = panelIsRightOfCard ? panelRect.left - width - gap : panelRect.right + gap;
    const preferredFits = preferredLeft >= margin && preferredLeft + width <= window.innerWidth - margin;
    const left = preferredFits ? preferredLeft : alternateLeft;
    preview.style.left = `${Math.round(Math.max(margin, Math.min(left, window.innerWidth - width - margin)))}px`;
    preview.style.top = `${Math.round(Math.max(margin, Math.min(panelRect.top, window.innerHeight - height - margin)))}px`;
  }

  function userStatValue(user, keys) {
    const sources = [user && user.user_summary, user, user && user.summary, user && user.user_stat, user && user.stats].filter(Boolean);
    for (const key of keys) {
      for (const source of sources) {
        const value = source[key];
        if (value != null && value !== '') return value;
      }
    }
    return null;
  }

  function userCardStat(value, label, href) {
    const num = Number(value);
    const inner = `<strong>${Number.isFinite(num) ? esc(num) : '-'}</strong><span>${esc(label)}</span>`;
    if (!href) return `<div class="ldp-user-card-stat">${inner}</div>`;
    return `<a class="ldp-user-card-stat" href="${escAttr(href)}" aria-label="查看${escAttr(label)}">${inner}</a>`;
  }

  function isSafeUserCardUrl(value) {
    const url = String(value || '').trim();
    return /^(https?:)?\/\//i.test(url) || url.startsWith('/') || url.startsWith('data:image/');
  }

  function sanitizeUserCardBioHtml(value) {
    const template = document.createElement('template');
    template.innerHTML = String(value || '');
    const allowedTags = new Set(['A', 'B', 'BR', 'EM', 'I', 'IMG', 'P', 'SPAN', 'STRONG']);
    const allowedAttrs = {
      A: new Set(['href']),
      IMG: new Set(['src', 'alt', 'class', 'width', 'height']),
      SPAN: new Set(['class']),
    };
    const cleanNode = (node) => {
      if (node.nodeType === Node.TEXT_NODE) return esc(node.textContent || '');
      if (node.nodeType !== Node.ELEMENT_NODE) return '';
      const tag = node.tagName;
      const children = Array.from(node.childNodes).map(cleanNode).join('');
      if (!allowedTags.has(tag)) return children;
      const attrs = Array.from(node.attributes)
          .filter((attr) => {
            const name = attr.name.toLowerCase();
            if (name.startsWith('on') || name === 'style') return false;
            if (!(allowedAttrs[tag] && allowedAttrs[tag].has(name))) return false;
            if ((name === 'href' || name === 'src') && !isSafeUserCardUrl(attr.value)) return false;
            return true;
          })
          .map((attr) => ` ${attr.name.toLowerCase()}="${escAttr(attr.value)}"`).join('');
      if (tag === 'A') return `<a${attrs} target="_blank" rel="noopener">${children}</a>`;
      if (tag === 'IMG') return `<img${attrs} loading="lazy" decoding="async">`;
      return `<${tag.toLowerCase()}${attrs}>${children}</${tag.toLowerCase()}>`;
    };
    return Array.from(template.content.childNodes).map(cleanNode).join('');
  }

  function userCardProgressHtml(phase) {
    if (phase === 'ready') return '';
    const loadingStats = phase === 'stats';
    const label = loadingStats ? '资料已获取，正在获取统计…' : '正在获取用户资料…';
    return `<div class="ldp-user-card-progress${loadingStats ? ' is-stats' : ''}" role="status" aria-live="polite">
      <span>${label}</span><span class="ldp-user-card-progress-track"><span class="ldp-user-card-progress-fill"></span></span>
    </div>`;
  }

  function userRegistrationDate(value) {
    const date = new Date(value || 0);
    if (!Number.isFinite(date.getTime())) return '';
    return `${date.getFullYear()} 年 ${date.getMonth() + 1} 月 ${date.getDate()} 日`;
  }

  function userRecentDate(value) {
    const date = new Date(value || 0);
    if (!Number.isFinite(date.getTime())) return '';
    const elapsed = Date.now() - date.getTime();
    if (elapsed >= 0 && elapsed < 60 * 1000) return '刚刚';
    if (elapsed >= 0 && elapsed < 60 * 60 * 1000) return `${Math.max(1, Math.floor(elapsed / 60000))} 分钟前`;
    if (elapsed >= 0 && elapsed < 24 * 60 * 60 * 1000) return `${Math.floor(elapsed / 3600000)} 小时前`;
    if (date.getFullYear() === new Date().getFullYear()) return `${date.getMonth() + 1} 月 ${date.getDate()} 日`;
    return userRegistrationDate(value);
  }

  function userVisibleGroups(groups) {
    const visible = new Map();
    (Array.isArray(groups) ? groups : []).forEach((group) => {
      const name = String(group && group.name || '').trim();
      if (!name || /^trust_level_[0-9]+$/i.test(name)) return;
      const key = name.toLocaleLowerCase();
      if (visible.has(key)) return;
      visible.set(key, {
        name,
        label: String(group.full_name || group.display_name || group.title || name).trim() || name,
      });
    });
    return Array.from(visible.values());
  }

  function userCardGroupsHtml(user) {
    const groups = userVisibleGroups([
      ...(Array.isArray(user && user.groups) ? user.groups : []),
      user && user.primary_group_name ? { name: user.primary_group_name } : null,
    ].filter(Boolean));
    if (!groups.length) return '';
    return `<div class="ldp-user-card-groups" aria-label="用户分组">
      <span>用户分组</span><div>${groups.map((group) => `<a href="${BASE}/g/${encodeURIComponent(group.name)}"
        target="_blank" rel="noopener" data-ldp-tooltip-label="进入 ${escAttr(group.label)} 分组">${esc(group.label)}</a>`).join('')}</div>
    </div>`;
  }

  function userProfileFactsHtml(user, variant, options = {}) {
    const fact = (label, value, factOptions = {}) => {
      if (value == null || value === '') return '';
      const classes = ['ldp-user-profile-fact'];
      if (factOptions.accent) classes.push('is-accent');
      if (factOptions.wide) classes.push('is-wide');
      const tooltip = factOptions.title ? ` data-ldp-tooltip-label="${escAttr(factOptions.title)}"` : '';
      return `<span class="${classes.join(' ')}"${tooltip}><span class="ldp-user-profile-fact-label">${esc(label)}</span><span class="ldp-user-profile-fact-value">${esc(value)}</span></span>`;
    };
    const numberValue = (keys) => {
      const value = userStatValue(user, keys);
      if (!options.emptyNumberAsZero && (value == null || value === '')) return '';
      const numeric = Number(value);
      return Number.isFinite(numeric) ? numeric.toLocaleString('zh-CN') : '';
    };
    const trustLabels = ['新用户', '基本用户', '成员', '活跃用户', '领导者'];
    const trustLevel = userTrustLevel(user);
    const groups = userVisibleGroups([
      ...(Array.isArray(user && user.groups) ? user.groups : []),
      options.includePrimaryGroup && user && user.primary_group_name ? { name: user.primary_group_name } : null,
    ].filter(Boolean));
    const groupText = groups.map((group) => group.label).join(', ');
    const facts = [
      fact('加入日期：', userRegistrationDate(user && user.created_at)),
      fact('最后一个帖子', userRecentDate(user && (user.last_posted_at || user.last_post_at))),
      fact('最后活动', userRecentDate(user && (user.last_seen_at || user.last_active_at))),
      fact('浏览量', numberValue(['profile_view_count', 'profile_views', 'views'])),
      fact('信任级别', Number.isFinite(trustLevel) ? (trustLabels[trustLevel] || `Lv${trustLevel}`) : ''),
      fact('电子邮件', user && user.email, { wide: true }),
      ...(variant === 'card' ? [] : [fact('群组', groupText, { accent: true, wide: true, title: options.groupTooltip ? groupText : '' })]),
      ...(variant === 'card' ? [] : [
        fact('正在关注', numberValue(['total_following', 'following_count', 'followings_count'])),
        fact('关注者', numberValue(['total_followers', 'follower_count', 'followers_count'])),
      ]),
      fact('点数', numberValue(['gamification_score', 'points']), { accent: true }),
    ].filter(Boolean);
    return facts.length ? `<div class="ldp-user-profile-facts is-${variant}">${facts.join('')}</div>` : '';
  }

  function userCardFollowStatsHtml(user, username, options = {}) {
    const interactive = options.interactive !== false;
    const configs = [
      { type: 'following', label: '关注', total: userStatValue(user, ['total_following', 'following_count', 'followings_count']), visible: user && user.can_see_following !== false },
      { type: 'followers', label: '被关注', total: userStatValue(user, ['total_followers', 'follower_count', 'followers_count']), visible: user && user.can_see_followers !== false },
    ];
    return `<div class="ldp-user-card-follow-stats" aria-label="用户关注关系">
      ${configs.map((item) => {
        const total = Number(item.total);
        const count = Number.isFinite(total) ? total.toLocaleString('zh-CN') : '-';
        if (!interactive) {
          return `<span class="ldp-user-card-follow-stat is-readonly" aria-label="${escAttr(`${item.label} ${count}`)}">
            <strong>${esc(count)}</strong><span>${esc(item.label)}</span>
          </span>`;
        }
        const label = item.visible ? `查看${item.label}人员` : `${item.label}列表不可见`;
        return `<button class="ldp-user-card-follow-stat" type="button" data-user-card-follow-type="${item.type}"
          data-username="${escAttr(username)}" aria-controls="ldp-user-card-follow-panel" aria-expanded="false"
          aria-label="${escAttr(label)}"${item.visible ? '' : ' disabled'}>
          <strong>${esc(count)}</strong><span>${esc(item.label)}</span>
        </button>`;
      }).join('')}
    </div>`;
  }

  function userCardFollowItemHtml(user) {
    const username = String(user && user.username || '');
    const name = String(user && user.name || username);
    const avatar = avatarWithFlairHtml(
      persistentAvatarHtml(user && user.avatar_template, 48, 'ldp-user-card-follow-avatar', name),
      user
    );
    return `<a class="ldp-user-card-follow-item ldp-user-link" href="${userProfileUrl(username)}" target="_blank" rel="noopener"
      role="listitem" data-user-card="${escAttr(username)}">
      ${avatar}<span><strong>${esc(name)}</strong><small>@${esc(username)}</small></span>
    </a>`;
  }

  function renderUserCardFollowList(panel) {
    if (panel?.hidden) return;
    const list = panel && panel.querySelector('.ldp-user-card-follow-list');
    const summary = panel && panel.querySelector('.ldp-user-card-follow-summary');
    const input = panel && panel.querySelector('input[type="search"]');
    const pagination = panel && panel.querySelector('.ldp-user-card-follow-pagination');
    if (!panel || !list || !summary || !input || !pagination) return;
    const users = Array.isArray(panel._ldpFollowUsers) ? panel._ldpFollowUsers : [];
    const query = normalizeSearchText(input.value);
    const matches = query ? users.filter((user) => user.searchText.includes(query)) : users;
    const pageCount = Math.max(1, Math.ceil(matches.length / USER_FOLLOW_LIST_PAGE_SIZE));
    const requestedPage = Math.max(0, Number(panel.dataset.followPage) || 0);
    const page = Math.min(requestedPage, pageCount - 1);
    const offset = page * USER_FOLLOW_LIST_PAGE_SIZE;
    const visible = matches.slice(offset, offset + USER_FOLLOW_LIST_PAGE_SIZE);
    panel.dataset.followPage = String(page);
    releasePersistentAvatarImages(list);
    list.innerHTML = visible.length
      ? visible.map(userCardFollowItemHtml).join('')
      : `<div class="ldp-user-card-follow-empty">${query ? '没有匹配的人员' : '暂无人员'}</div>`;
    summary.textContent = query ? `找到 ${matches.length} 人` : `${matches.length} 人`;
    pagination.hidden = matches.length <= USER_FOLLOW_LIST_PAGE_SIZE;
    pagination.querySelector('span').textContent = `${page + 1} / ${pageCount}`;
    pagination.querySelector('[data-user-card-follow-page="previous"]').disabled = page === 0;
    pagination.querySelector('[data-user-card-follow-page="next"]').disabled = page >= pageCount - 1;
    list.scrollTop = 0;
    hydratePersistentAvatarImages(list, POST_REQUEST_PRIORITY.userCard);
  }

  function connectNumber(value) {
    const match = String(value || '').replace(/,/g, '').match(/-?\d+/);
    return match ? Number(match[0]) : 0;
  }

  function connectCurrentTarget(value) {
    const parts = String(value || '').replace(/,/g, '').split('/');
    if (parts.length >= 2) return { current: connectNumber(parts[0]), target: connectNumber(parts[1]) };
    const numbers = String(value || '').replace(/,/g, '').match(/-?\d+/g) || [];
    return { current: Number(numbers[0] || 0), target: Number(numbers[1] || 0) };
  }

  function parseConnectTrustHtml(html) {
    const doc = new globalThis.DOMParser().parseFromString(String(html || ''), 'text/html');
    const card = Array.from(doc.querySelectorAll('.card')).find((candidate) => {
      const heading = candidate.querySelector('.card-title,h2');
      return heading && /信任级别\s*\d+\s*的要求/.test(heading.textContent || '');
    });
    if (!card) throw new Error('Connect 未返回升级要求，请先登录 Connect');
    const heading = String(card.querySelector('.card-title,h2')?.textContent || '').trim();
    const targetLevel = Number((heading.match(/信任级别\s*(\d+)\s*的要求/) || [])[1]);
    const subtitle = String(card.querySelector('.card-subtitle')?.textContent || '').trim();
    const username = (subtitle.match(/@([^\s·]+)/) || [])[1] || '';
    const timePeriod = Number((subtitle.match(/过去\s*([\d,]+)\s*天/) || [])[1]?.replace(/,/g, '')) || 100;
    const rings = Array.from(card.querySelectorAll('.tl3-ring')).map((item) => ({
      label: String(item.querySelector('.tl3-ring-label')?.textContent || '').trim(),
      current: connectNumber(item.querySelector('.tl3-ring-current')?.textContent),
      target: connectNumber(item.querySelector('.tl3-ring-target')?.textContent),
      met: item.querySelector('.tl3-ring-circle')?.classList.contains('met') || false,
    })).filter((item) => item.label);
    const requirementGroups = [
      ['bars', '.tl3-bar-item', '.tl3-bar-label', '.tl3-bar-nums'],
      ['quotas', '.tl3-quota-card', '.tl3-quota-label', '.tl3-quota-nums'],
      ['vetoes', '.tl3-veto-item', '.tl3-veto-label', '.tl3-veto-value'],
    ];
    const { bars, quotas, vetoes } = Object.fromEntries(requirementGroups.map(([
      group, itemSelector, labelSelector, valueSelector,
    ]) => [group, Array.from(card.querySelectorAll(itemSelector)).map((item) => {
      const valueNode = item.querySelector(valueSelector);
      const values = group === 'vetoes'
        ? { current: connectNumber(valueNode?.textContent), target: 0 }
        : connectCurrentTarget(valueNode?.textContent);
      const met = group === 'bars'
        ? valueNode?.classList.contains('met') || item.querySelector('.tl3-bar-fill')?.classList.contains('met') || false
        : item.classList.contains('met') || (group === 'quotas' ? values.current <= values.target : values.current === 0);
      return {
        label: String(item.querySelector(labelSelector)?.textContent || '').trim(),
        ...values, met, ...(group === 'bars' ? {} : { reverse: true }),
      };
    }).filter((item) => item.label)]));
    const statusNode = card.querySelector('.status-met,.status-unmet');
    const badgeNode = card.querySelector('.badge');
    const allRequirements = [...rings, ...bars, ...quotas, ...vetoes];
    const met = statusNode
      ? statusNode.classList.contains('status-met')
      : badgeNode ? !/未达到|未达/.test(badgeNode.textContent || '') : allRequirements.every((item) => item.met);
    return {
      targetLevel: Number.isFinite(targetLevel) ? targetLevel : null,
      username,
      timePeriod,
      rings,
      bars,
      quotas,
      vetoes,
      met,
    };
  }

  function requestConnectTrustHtml() {
    const request = globalThis.GM_xmlhttpRequest || globalThis.GM?.xmlHttpRequest;
    if (typeof request !== 'function') return Promise.reject(new Error('当前脚本未获得 Connect 跨域读取权限'));
    return new Promise((resolve, reject) => {
      request({
        method: 'GET',
        url: 'https://connect.linux.do/',
        headers: { 'Accept': 'text/html' },
        timeout: 20000,
        onload: (response) => {
          if (response.status >= 200 && response.status < 300) resolve(response.responseText || '');
          else reject(new Error(`Connect 请求失败（${response.status || '未知状态'}）`));
        },
        ontimeout: () => reject(new Error('Connect 请求超时')),
        onerror: () => reject(new Error('Connect 请求失败')),
      });
    });
  }

  function fetchConnectTrustData(force = false, persistedCache = null) {
    const freshFor = 5 * MINUTE;
    if (!CONNECT_TRUST_CACHE && persistedCache && persistedCache.data) {
      CONNECT_TRUST_CACHE = {
        data: persistedCache.data,
        cachedAt: Number(persistedCache.cachedAt || 0),
      };
    }
    if (CONNECT_TRUST_REQUEST) return CONNECT_TRUST_REQUEST;
    if (!force && CONNECT_TRUST_CACHE && Date.now() - CONNECT_TRUST_CACHE.cachedAt < freshFor) {
      return Promise.resolve(CONNECT_TRUST_CACHE.data);
    }
    CONNECT_TRUST_REQUEST = requestConnectTrustHtml().then(parseConnectTrustHtml).then((data) => {
      CONNECT_TRUST_CACHE = { data, cachedAt: Date.now() };
      return data;
    }).finally(() => {
      CONNECT_TRUST_REQUEST = null;
    });
    return CONNECT_TRUST_REQUEST;
  }

  function settingsUserProfileHtml(user) {
    const username = String(user && user.username || ME_USERNAME || '');
    const name = String(user && user.name || username);
    const trustLevel = userTrustLevel(user);
    const background = String(user && (
      user.card_background_upload_url || user.profile_background_upload_url
    ) || '').trim();
    const avatar = avatarWithFlairHtml(
      persistentAvatarHtml(user && user.avatar_template, 144, 'ldp-user-info-avatar-image', name),
      user
    );
    const title = String(user && (user.title || user.flair_name) || '').trim();
    const titleFlair = userFlairHtml(user);
    const bio = String(user && (user.bio_excerpt || user.bio_raw) || '').trim();
    const website = String(user && (user.website_name || user.website) || '').trim();
    const websiteUrl = String(user && (user.website || user.website_name) || '').trim();
    const safeWebsite = websiteUrl && isSafeUserCardUrl(websiteUrl)
      ? (websiteUrl.startsWith('/') ? `${BASE}${websiteUrl}` : websiteUrl)
      : '';
    return `<section class="ldp-user-info-profile" aria-label="当前用户资料">
      <div class="ldp-user-info-cover">${background && isSafeUserCardUrl(background) ? `<img src="${escAttr(absoluteImageUrl(background))}" alt="" loading="lazy" decoding="async">` : ''}</div>
      <div class="ldp-user-info-profile-body">
        <div class="ldp-user-info-avatar">${avatar || esc(name.slice(0, 1).toUpperCase())}</div>
        <div class="ldp-user-info-identity">
          <div class="ldp-user-info-name-row"><strong class="ldp-user-info-name">${esc(name)}</strong>${Number.isFinite(trustLevel) ? `<span class="ldp-user-info-level">Lv${trustLevel}</span>` : ''}</div>
          <div class="ldp-user-info-username">@${esc(username)}</div>
          ${title ? `<div class="ldp-user-info-title">${titleFlair}${esc(title)}</div>` : ''}
          ${safeWebsite ? `<a class="ldp-user-info-site" href="${escAttr(safeWebsite)}" target="_blank" rel="noopener">${icon('externalLink')}<span>${esc(website || websiteUrl)}</span></a>` : ''}
        </div>
        ${bio ? `<div class="ldp-user-info-bio">${sanitizeUserCardBioHtml(bio)}</div>` : ''}
        ${userProfileFactsHtml(user, 'settings', { emptyNumberAsZero: true })}
      </div>
    </section>`;
  }

  function connectProgress(item) {
    if (item.reverse) {
      if (item.target === 0) return 100;
      return Math.max(0, Math.min(100, item.current / item.target * 100));
    }
    return Math.max(0, Math.min(100, item.target > 0 ? item.current / item.target * 100 : item.met ? 100 : 0));
  }

  function connectAchievementClass(item) {
    if (item.reverse || !(item.target > 0) || item.current < item.target) return '';
    const ratio = item.current / item.target;
    if (ratio >= 10) return ' is-goal is-over is-over-high is-over-ultra is-over-epic';
    if (ratio >= 5) return ' is-goal is-over is-over-high is-over-ultra';
    if (ratio >= 2) return ' is-goal is-over is-over-high';
    if (ratio > 1) return ' is-goal is-over';
    return ' is-goal';
  }

  function connectMetricBelowTarget(item) {
    return !item.reverse && Number(item.target) > 0 && Number(item.current) < Number(item.target);
  }

  const CONNECT_REQUIREMENT_HELP = [
    [/访问天数|days?visited/, (period) => `访问天数：过去 ${period} 天内，访问站点并至少阅读过 1 个帖子的不同自然日数量。`],
    [/浏览话题|topics?viewed/, (period) => `浏览话题：过去 ${period} 天内浏览过的公开话题数量；目标按同期公开话题总量的一定比例计算，并受站点上限限制。`],
    [/浏览帖子|posts?read/, (period) => `浏览帖子：过去 ${period} 天内实际读过的公开帖子数量；目标按同期公开帖子总量的一定比例计算，并受站点上限限制。`],
    [/回复话题|topics?replied/, (period) => `回复话题：过去 ${period} 天内回复过的不同公开话题数量；同一话题回复多次仍只计 1 个。`],
    [/获赞天数|likes?received.*days/, (period) => `获赞天数：过去 ${period} 天内至少收到过 1 个赞的不同自然日数量；同一天收到多个赞仍只计 1 天。`],
    [/获赞用户|likes?received.*users/, (period) => `获赞用户：过去 ${period} 天内给你点过赞的不同用户数量；同一用户多次点赞仍只计 1 人。`],
    [/^获赞$|likes?received/, (period) => `获赞：过去 ${period} 天内，你在公开话题中的帖子收到的点赞总数。`],
    [/^点赞$|likes?given/, (period) => `点赞：过去 ${period} 天内，你在公开话题中送出的点赞总数。`],
    [/被举报帖子|flaggedposts/, (period) => `被举报帖子：过去 ${period} 天内，被其他用户举报且经管理确认的不同帖子数量。这是上限项，数值越少越好。`],
    [/举报用户|userswhoflagged|flaggedbyusers/, (period) => `举报用户：过去 ${period} 天内，对你的帖子发起且经管理确认举报的不同用户数量；不是你举报了多少人。这是上限项，数值越少越好。`],
    [/被禁言|silenced/, () => '被禁言：过去 6 个月内的禁言处罚记录，当前仍在禁言也会计入；此项必须为 0。'],
    [/被封禁|suspended/, () => '被封禁：过去 6 个月内的封禁处罚记录，当前仍在封禁也会计入；此项必须为 0。'],
  ];

  function connectRequirementHelp(label, timePeriod = 100) {
    const normalized = String(label || '').replace(/\s+/g, '').toLowerCase();
    const period = Number.isFinite(Number(timePeriod)) && Number(timePeriod) > 0 ? Number(timePeriod) : 100;
    const match = CONNECT_REQUIREMENT_HELP.find(([pattern]) => pattern.test(normalized));
    return match ? match[1](period) : '';
  }

  function settingsConnectHtml(data, error) {
    if (!data) return `<section class="ldp-connect-card"><div class="ldp-connect-head"><div class="ldp-connect-heading"><strong>Connect 升级进度</strong><small>升级要求来自 connect.linux.do</small></div></div><div class="ldp-connect-error"><span>${esc(error && error.message || '暂时无法读取 Connect 数据')}</span></div></section>`;
    const timePeriod = Number(data.timePeriod) > 0 ? Number(data.timePeriod) : 100;
    const valueLabel = (item) => `${Number(item.current).toLocaleString('zh-CN')} / ${Number(item.target).toLocaleString('zh-CN')}`;
    const style = (item, forceDanger = false) => `--ldp-connect-progress:${connectProgress(item).toFixed(1)}%;--ldp-connect-color:${forceDanger || connectMetricBelowTarget(item) || !item.met ? 'var(--danger,#c84545)' : 'var(--tertiary,#47855f)'}`;
    const metricHelp = (item) => {
      const help = connectRequirementHelp(item.label, timePeriod);
      return help ? ` data-ldp-tooltip-label="${escAttr(help)}"` : '';
    };
    const barGroup = (title, items) => items.length ? `<div class="ldp-connect-group"><div class="ldp-connect-group-title">${title}</div><div class="ldp-connect-bars">${items.map((item) => `<div class="ldp-connect-bar ldp-connect-metric${connectMetricBelowTarget(item) ? ' is-short' : ''}${connectAchievementClass(item)}" style="${style(item)}"${metricHelp(item)}><div class="ldp-connect-bar-copy"><span>${esc(item.label)}</span><strong>${esc(valueLabel(item))}</strong></div><div class="ldp-connect-bar-track"><span class="ldp-connect-bar-fill"></span></div></div>`).join('')}</div></div>` : '';
    const quotaItems = [...data.quotas, ...data.vetoes];
    const participationGroup = barGroup('参与互动', data.bars);
    const complianceGroup = quotaItems.length ? `<div class="ldp-connect-group"><div class="ldp-connect-group-title">合规记录</div><div class="ldp-connect-quotas">${quotaItems.map((item) => `<div class="ldp-connect-quota ldp-connect-metric" style="${style(item, Number(item.current) > 0)}"${metricHelp(item)}><div class="ldp-connect-quota-copy"><span>${esc(item.label)}</span><strong>${esc(valueLabel(item))}</strong></div><div class="ldp-connect-bar-track"><span class="ldp-connect-bar-fill"></span></div></div>`).join('')}</div></div>` : '';
    return `<section class="ldp-connect-card" aria-label="Connect 升级进度">
      <div class="ldp-connect-head"><div class="ldp-connect-heading"><strong>信任级别 ${esc(data.targetLevel == null ? '' : data.targetLevel)} 的要求</strong><small>${data.username ? `@${esc(data.username)} · ` : ''}过去 ${esc(timePeriod)} 天的数据</small></div><span class="ldp-connect-status ldp-connect-metric${data.met ? '' : ' is-unmet'}" data-ldp-tooltip-label="所有项目需要同时达标。互动与活跃项须达到下限；合规项不得超过上限，并在存在记录时以红色提醒。">${data.met ? '已达到' : '未达到'}</span></div>
      ${data.rings.length ? `<div class="ldp-connect-rings">${data.rings.map((item) => `<div class="ldp-connect-ring ldp-connect-metric" style="${style(item)}"${metricHelp(item)}><div class="ldp-connect-ring-visual"><span class="ldp-connect-ring-value">${esc(Number(item.current).toLocaleString('zh-CN'))}<small>/ ${esc(Number(item.target).toLocaleString('zh-CN'))}</small></span></div><span class="ldp-connect-ring-label">${esc(item.label)}</span></div>`).join('')}</div>` : ''}
      ${participationGroup || complianceGroup ? `<div class="ldp-connect-detail-groups">${participationGroup}${complianceGroup}</div>` : ''}
      ${error ? `<div class="ldp-connect-error"><span>当前显示缓存数据；${esc(error.message || '联网更新失败')}</span></div>` : ''}
    </section>`;
  }

  function renderSettingsUserInfo(container, user, connectData, connectError) {
    if (!container) return;
    const selectedView = ['connect', 'profile'].includes(container.dataset.userInfoView)
      ? container.dataset.userInfoView
      : 'connect';
    container.dataset.userInfoView = selectedView;
    container.innerHTML = `<div class="ldp-user-info-tabs" role="tablist" aria-label="用户信息分类">
        <button class="ldp-user-info-tab${selectedView === 'connect' ? ' active' : ''}" type="button" role="tab" data-user-info-view="connect" aria-selected="${selectedView === 'connect'}">${icon('activity')}<span>Connect</span></button>
        <button class="ldp-user-info-tab${selectedView === 'profile' ? ' active' : ''}" type="button" role="tab" data-user-info-view="profile" aria-selected="${selectedView === 'profile'}">${icon('userRound')}<span>基本信息</span></button>
      </div>
      <div class="ldp-user-info-view" role="tabpanel" data-user-info-panel="connect"${selectedView === 'connect' ? '' : ' hidden'}>${settingsConnectHtml(connectData, connectError)}</div>
      <div class="ldp-user-info-view" role="tabpanel" data-user-info-panel="profile"${selectedView === 'profile' ? '' : ' hidden'}>${settingsUserProfileHtml(user)}</div>`;
    hydratePersistentAvatarImages(container, POST_REQUEST_PRIORITY.userCard);
    syncReaderSvgSymbols(container);
  }

  function userCardActionsHtml(user, username) {
    const privateMessageUnavailable = user && (
      user.can_send_private_message_to_user === false || user.can_send_private_messages === false
    );
    const followed = !!(user && user.is_followed);
    const followUnavailable = !!(user && user.can_follow === false && !followed);
    const endorsementUnavailable = !!(user && user.category_expert_endorsements === null);
    const notificationLevel = userNotificationLevel(user);
    const notificationUnavailable = !!(user && user.can_mute_user === false
      && user.can_ignore_user === false && notificationLevel === 'normal');
    const actions = [
      { action: 'message', icon: 'mail', label: privateMessageUnavailable ? '私信（当前不可用）' : '私信', disabled: privateMessageUnavailable },
      { action: 'notifications', icon: 'bell', label: notificationUnavailable ? '消息设置（当前不可用）' : `消息设置：${USER_NOTIFICATION_LEVEL_LABELS[notificationLevel]}`, active: notificationLevel !== 'normal', disabled: notificationUnavailable, expanded: true },
      { action: 'endorse', icon: 'award', label: endorsementUnavailable ? '认可（当前不可用）' : '认可', disabled: endorsementUnavailable },
      { action: 'follow', icon: 'userPlus', label: followUnavailable ? '关注（当前不可用）' : (followed ? '取消关注' : '关注'), active: followed, disabled: followUnavailable },
    ];
    const notificationOptions = [
      { level: 'normal', icon: 'bell', label: '常规', description: '回复、引用或提到您时正常通知。' },
      ...(user && user.can_mute_user === false ? [] : [
        { level: 'mute', icon: 'bellOff', label: '免打扰', description: '不接收此用户的通知、私信和直接聊天。' },
      ]),
      ...(user && user.can_ignore_user === false ? [] : [
        { level: 'ignore', icon: 'eyeOff', label: '忽略', description: '隐藏此用户的内容，并停止相关通知。' },
      ]),
    ];
    return `<div class="ldp-user-card-actions-wrap">
      <div class="ldp-user-card-actions" role="toolbar" aria-label="用户操作">
        ${actions.map((item) => `<button type="button" class="ldp-user-card-action${item.active ? ' is-active' : ''}"
          data-user-card-action="${item.action}" data-username="${escAttr(username)}"
          data-tooltip="${escAttr(item.label)}" aria-label="${escAttr(item.label)}"${item.expanded ? ' aria-expanded="false"' : ''}${item.disabled ? ' disabled' : ''}>
          ${icon(item.icon)}
        </button>`).join('')}
      </div>
      <div class="ldp-user-card-notification-menu" role="menu" aria-label="消息设置" hidden>
        ${notificationOptions.map((item) => `<button type="button" role="menuitemradio"
          class="ldp-user-card-notification-option${item.level === notificationLevel ? ' is-active' : ''}"
          data-user-notification-level="${item.level}" aria-checked="${item.level === notificationLevel}">
          ${icon(item.icon)}<span class="ldp-user-card-notification-option-copy">
            <strong>${item.label}</strong><small>${item.description}</small>
          </span>
        </button>`).join('')}
      </div>
    </div>`;
  }

  function userCardHomeHtml(username) {
    return `<a class="ldp-user-card-home" href="${userProfileUrl(username)}" target="_blank" rel="noopener"
      data-tooltip="进入用户空间" aria-label="进入用户空间">${icon('externalLink')}</a>`;
  }

  function userCardBackgroundHtml(user) {
    const backgroundUrl = String(user && (
      user.card_background_upload_url || user.cardBackgroundUploadUrl ||
      user.profile_background_upload_url || user.profileBackgroundUploadUrl
    ) || '').trim();
    if (!backgroundUrl || !isSafeUserCardUrl(backgroundUrl)) return '';
    const source = absoluteImageUrl(backgroundUrl);
    return `<button class="ldp-user-card-background" type="button" data-user-card-background
      data-background-url="${escAttr(source)}" aria-label="预览用户背景图">
      <img src="${escAttr(source)}" alt="" loading="lazy" decoding="async">
    </button>`;
  }

  function userCardBadgeHash(badge) {
    const identity = `${badge && badge.id || ''}|${badge && badge.name || ''}|${badge && badge.icon || ''}`;
    let hash = 2166136261;
    for (let index = 0; index < identity.length; index++) {
      hash ^= identity.charCodeAt(index);
      hash = Math.imul(hash, 16777619);
    }
    return hash >>> 0;
  }

