      resourceMonitorState.longTasksAvailable = observeResourceMonitorPerformance(
        resourceMonitorLongTasksSupported, 'longTaskObserver', 'longtask', (list, ...callbackArgs) => {
            resourceMonitorRecordDroppedEntries('Long Tasks', callbackArgs[1]);
            list.getEntries().forEach((entry) => {
              const startedAt = window.performance.timeOrigin + Number(entry.startTime || 0);
              const duration = Math.max(0, Number(entry.duration) || 0);
              resourceMonitorPushTimedEvent(startedAt, {
                scope: 'shared',
                kind: 'longtask',
                duration,
                detail: `页面共享主线程长任务 ${resourceMonitorDuration(duration)}`,
                basis: 'PerformanceLongTaskTiming · 1ms',
              });
            });
          });
      observeResourceMonitorPerformance(
        resourceMonitorLongFramesSupported, 'longFrameObserver', 'long-animation-frame', (list, ...callbackArgs) => {
            resourceMonitorRecordDroppedEntries('Long Animation Frames', callbackArgs[1]);
            list.getEntries().forEach((entry) => {
              const startedAt = window.performance.timeOrigin + Number(entry.startTime || 0);
              const frameDuration = Math.max(0, Number(entry.duration) || 0);
              const blockingDuration = Math.max(0, Number(entry.blockingDuration) || 0);
              resourceMonitorPushTimedEvent(startedAt, {
                scope: 'shared',
                kind: 'frame',
                duration: frameDuration,
                detail: `长动画帧 ${resourceMonitorDuration(frameDuration)} · 阻塞 ${resourceMonitorDuration(blockingDuration)}`,
                basis: 'Long Animation Frames',
              });
              const groups = new Map();
              Array.from(entry.scripts || []).forEach((script) => {
                const duration = Math.max(0, Number(script.duration) || 0);
                if (!duration) return;
                const scope = resourceMonitorScriptScope(script);
                const group = groups.get(scope) || { duration: 0, forced: 0, count: 0, labels: [] };
                group.duration += duration;
                group.forced += Math.max(0, Number(script.forcedStyleAndLayoutDuration) || 0);
                group.count++;
                if (group.labels.length < 2) group.labels.push(resourceMonitorScriptLabel(script));
                groups.set(scope, group);
              });
              groups.forEach((group, scope) => {
                resourceMonitorPushTimedEvent(startedAt, {
                  scope,
                  kind: 'script',
                  duration: group.duration,
                  detail: `长帧内已归因脚本 ${resourceMonitorDuration(group.duration)}${group.forced ? ` · 强制布局 ${resourceMonitorDuration(group.forced)}` : ''} · ${group.labels.join(' / ')}`,
                  basis: `PerformanceScriptTiming · ${group.count} 段`,
                });
              });
            });
          });
